INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTB_2016_parent', 'VTB', 2016, 'parent', 'Doanh nghiệp có giao dịch mua bán lớn với các công ty con, đặc biệt khoản phải trả cho Công ty CP Công nghệ thông tin VTB lên tới 289 tỷ VND. Các giao dịch này chủ yếu là thương mại thông thường, không có dấu hiệu cho vay không lãi suất hay mua bán chênh lệch bất thường. Tuy nhiên, quy mô giao dịch lớn đòi hỏi kiểm soát chặt chẽ.', 'Nợ vay ngắn hạn 12 tỷ VND với lãi suất 7.5%/năm, được đảm bảo bằng nhà xưởng và quyền sử dụng đất. Áp lực nợ ở mức vừa phải so với tổng tài sản 705 tỷ VND và dòng tiền kinh doanh dương. Công ty có khả năng thanh toán nợ.', 'Hàng tồn kho tăng mạnh từ 83 tỷ lên 104 tỷ VND, chủ yếu là nguyên liệu và thành phẩm. Không có dự phòng giảm giá hàng tồn kho. Cần theo dõi khả năng tiêu thụ và nguy cơ ứ đọng hàng tồn kho nếu doanh thu không tăng tương ứng.', 5, 'Doanh thu thuần tăng trưởng mạnh 121.7% đạt 737.5 tỷ VND, lợi nhuận sau thuế tăng 29.6% đạt 15.8 tỷ VND. Tuy nhiên, nợ phải trả tăng vọt từ 132 tỷ lên 494 tỷ VND, đặc biệt phải trả người bán ngắn hạn tăng mạnh. Hàng tồn kho tăng 25%. Dòng tiền hoạt động kinh doanh dương 22.9 tỷ VND hỗ trợ thanh toán. Công ty đang trong giai đoạn mở rộng kinh doanh nhưng cần kiểm soát tốt đòn bẩy tài chính và quản lý hàng tồn kho.'),
('VTB_2016_consolidated', 'VTB', 2016, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan, đặc biệt là mua hàng từ Công ty CP Công nghệ thông tin VTB với giá trị 419 tỷ VNĐ và bán hàng cho Công ty CP Thương mại JS VTB với giá trị 64 tỷ VNĐ. Điều này có thể tạo ra rủi ro về giá cả hoặc phụ thuộc vào các công ty con. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất.', 'Nợ vay ngắn hạn là 12 tỷ VNĐ, được đảm bảo bằng nhà xưởng và quyền sử dụng đất. Áp lực nợ vay không cao do tổng tài sản lớn (790 tỷ VNĐ) và lãi vay chỉ 557 triệu VNĐ, cho thấy khả năng thanh toán tốt.', 'Hàng tồn kho cuối năm là 205 tỷ VNĐ, bao gồm hàng hóa mua đang đi đường, nguyên liệu, thành phẩm và hàng hóa. Có dự phòng giảm giá 507 triệu VNĐ cho hàng hóa. Dự án xây dựng dở dang trị giá 3.6 tỷ VNĐ, nhưng không có thông tin về sự chậm trễ hay ứ đọng.', 5, 'Doanh nghiệp có sức khỏe tài chính ổn định với lợi nhuận sau thuế tăng từ 13.4 tỷ lên 16.5 tỷ VNĐ. Doanh thu tăng mạnh, nhưng tỷ suất lợi nhuận gộp giảm. Rủi ro chủ yếu từ giao dịch bên liên quan và tồn kho. Triển vọng đầu tư trung bình.'),
('VTB_2015_parent', 'VTB', 2015, 'parent', 'Công ty có nhiều giao dịch lớn với các công ty con (JS VTB, Vitek VTB Hà Nội, CNTT VTB) với tổng phải thu khách hàng là bên liên quan lên đến hơn 35 tỷ VNĐ. Đặc biệt, khoản trả trước cho Công ty TNHH MTV Dịch vụ Công Ích Quận 2 trị giá 8.33 tỷ VNĐ đã phát sinh từ nhiều năm nhưng chưa hoàn thiện thủ tục thuê đất chính thức - đây là rủi ro lớn về quyền sở hữu tài sản. Công ty cũng đầu tư vào 3 công ty con với tổng giá trị gốc 9.71 tỷ VNĐ nhưng đã trích lập dự phòng giảm giá 5.675 tỷ VNĐ, cho thấy hiệu quả hoạt động của các công ty con không tốt.', 'Nợ vay ngắn hạn chỉ còn 20.35 tỷ VNĐ (giảm từ 23.9 tỷ VNĐ đầu năm), tỷ lệ nợ thuần/vốn chủ sở hữu ở mức thấp 7.15%. Tuy nhiên, toàn bộ khoản vay được đảm bảo bằng quyền sử dụng đất và tài sản trên đất trị giá hơn 43 tỷ VNĐ, cho thấy tài sản thế chấp dồi dào. Áp lực nợ vay ở mức kiểm soát được.', 'Hàng tồn kho tăng mạnh 47.7% từ 56.2 tỷ lên 83.0 tỷ VNĐ, trong đó nguyên vật liệu tăng gấp 2.6 lần (từ 18.9 tỷ lên 49.1 tỷ VNĐ). Điều này có thể phản ánh hoạt động mua sắm tích cực cho sản xuất nhưng cũng tiềm ẩn rủi ro ứ đọng nếu nhu cầu thị trường giảm. Không có dự phòng giảm giá hàng tồn kho nào được trích lập.', 6, 'Doanh thu năm 2015 tăng trưởng mạnh 73.5% đạt 332.4 tỷ VNĐ, nhưng lợi nhuận sau thuế giảm 14.5% xuống 12.2 tỷ VNĐ do biên lợi nhuận gộp giảm từ 21.5% xuống 15.8%. Công ty có cấu trúc vốn an toàn với tỷ lệ nợ thấp, nhưng tồn kho tăng đột biến cần được theo dõi. Rủi ro lớn nhất là khoản trả trước thuê đất 8.33 tỷ chưa hoàn thiện thủ tục và hiệu quả hoạt động kém của các công ty con (dự phòng giảm giá đầu tư 5.675 tỷ VNĐ). Công ty duy trì được dòng tiền hoạt động kinh doanh dương 11 tỷ VNĐ và thanh khoản tốt với tiền mặt 5.5 tỷ VNĐ.'),
('VTB_2015_consolidated', 'VTB', 2015, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho công ty mẹ và lương cho ban giám đốc, nhưng có khoản trả trước dài hạn cho Công ty TNHH MTV Dịch vụ Công Ích Quận 2 thuê đất chưa hoàn thiện thủ tục, tiềm ẩn rủi ro pháp lý.', 'Nợ vay ngắn hạn với tài sản thế chấp là quyền sử dụng đất, tỷ lệ nợ thuần trên vốn chủ sở hữu thấp (6.79%), áp lực nợ vay không cao.', 'Hàng tồn kho tăng đáng kể, có dự phòng giảm giá cho hàng hóa, nhưng không có dấu hiệu ứ đọng nghiêm trọng; dự án xây dựng dở dang không lớn.', 5, 'Công ty có doanh thu tăng mạnh, lợi nhuận gộp cao, nhưng lợi nhuận sau thuế giảm. Quản trị có một số rủi ro từ giao dịch với bên liên quan và khoản trả trước đất chưa hoàn tất. Nợ vay thấp, thanh khoản đủ, triển vọng trung bình.'),
('VTA_2025_consolidated', 'VTA', 2025, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là cổ đông lớn Tổng Công ty Vật liệu Xây dựng số 1 - CTCP, bao gồm mua bán hàng hóa và cho vay với lãi suất ưu đãi (0.2%/tháng). Không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn, tuy nhiên sự phụ thuộc vào cổ đông lớn là đáng lưu ý.', 'Công ty có áp lực nợ vay rất lớn, nợ ngắn hạn vượt quá tài sản ngắn hạn 49.137.482.604 VND. Tổng nợ vay là 21.655.822.440 VND, bao gồm nợ vay ngân hàng và nợ cổ đông lớn. Khả năng thanh toán thấp, tài sản thế chấp chủ yếu là quyền sử dụng đất và máy móc thiết bị sản xuất đã ngừng hoạt động.', 'Hàng tồn kho giảm mạnh từ 53.891.198.181 VND xuống 4.582.067.892 VND do Công ty ngừng sản xuất từ tháng 11/2024. Dự phòng giảm giá hàng tồn kho tăng từ 19.842.083.791 VND lên 14.736.426.050 VND (chiếm tỷ trọng lớn), cho thấy rủi ro tồn kho ứ đọng và mất giá trị cao.', 7, 'Công ty đang trong tình trạng tài chính rất khó khăn: ngừng hoạt động sản xuất, lỗ lũy kế 102.243.618.746 VND, thâm hụt vốn chủ sở hữu 11.461.418.746 VND. Khả năng hoạt động liên tục phụ thuộc vào kế hoạch tái cơ cấu. Triển vọng đầu tư tiêu cực trong ngắn hạn.'),
('VTA_2024_consolidated', 'VTA', 2024, 'consolidated', 'Doanh thu và chi phí mua hàng phụ thuộc lớn vào cổ đông lớn Tổng Công ty Vật liệu Xây dựng Số 1 - CTCP. Có giao dịch mua bán và vay lãi suất thấp (0.2%/tháng) với bên liên quan. Tổng các khoản phải trả cho bên liên quan chiếm tỷ trọng cao trong nợ phải trả ngắn hạn.', 'Rủi ro nợ rất cao. Nợ ngắn hạn vượt quá tài sản ngắn hạn 47 tỷ VNĐ. Tổng nợ phải trả (110 tỷ VNĐ) gấp gần 20 lần vốn chủ sở hữu (5.6 tỷ VNĐ). Phần lớn tài sản cố định đã được thế chấp cho các khoản vay ngân hàng. Công ty đã ngừng sản xuất và đang trong quá trình thanh lý tài sản.', 'Rủi ro tồn kho cực kỳ cao. Hàng tồn kho (chủ yếu là thành phẩm gạch) có giá trị ghi sổ lớn (73.7 tỷ VNĐ) nhưng đã trích lập dự phòng giảm giá khổng lồ (19.8 tỷ VNĐ). Công ty đã ngưng sản xuất, khả năng tiêu thụ và thu hồi giá trị từ hàng tồn kho rất thấp.', 8, 'Công ty đang trong tình trạng tài chính nghiêm trọng, với thua lỗ lũy kế lớn, dòng tiền kinh doanh âm, và vi phạm nghiêm trọng về khả năng thanh toán. Sự phụ thuộc vào giao dịch với cổ đông lớn, lượng hàng tồn kho khó tiêu thụ và việc ngừng sản xuất đặt ra nghi ngờ lớn về khả năng hoạt động liên tục. Tuy nhiên, các động thái thanh lý tài sản, tái cơ cấu nhân sự và kế hoạch từ Hội đồng Quản trị cho thấy nỗ lực cứu vãn tình hình.'),
('VTA_2023_consolidated', 'VTA', 2023, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan, đặc biệt là Tổng Công ty Vật liệu Xây dựng Số 1 - CTCP (cổ đông lớn 30,75%). Doanh thu bán hàng cho bên liên quan chiếm khoảng 70% tổng doanh thu (106.106 tỷ/152.366 tỷ), mua hàng từ bên liên quan chiếm khoảng 33% (50.680 tỷ/~152 tỷ). Công ty cho vay với lãi suất 0,2%/tháng đối với cổ đông lớn, thấp hơn thị trường. Phải thu từ cổ đông lớn là 6,58 tỷ VND, phải trả cho cổ đông lớn là 9,85 tỷ VND. Có dấu hiệu phụ thuộc lớn vào hệ sinh thái của Tổng Công ty Vật liệu Xây dựng Số 1.', 'Nợ ngắn hạn vượt tài sản ngắn hạn 28,1 tỷ VND, là dấu hiệu mất cân đối nghiêm trọng. Tổng nợ phải trả 133,9 tỷ VND trên tổng tài sản 174 tỷ VND (hệ số nợ ~77%). Lỗ lũy kế 50,7 tỷ VND, vốn chủ sở hữu chỉ còn 40 tỷ VND. Chi phí lãi vay năm 2023 là 3,2 tỷ VND. Toàn bộ tài sản cố định trị giá 30,8 tỷ VND đã được thế chấp cho ngân hàng BIDV. Công ty phụ thuộc lớn vào nguồn vốn lưu động từ ngân hàng BIDV (29,4 tỷ VND ngắn hạn) và cổ đông lớn.', 'Hàng tồn kho tổng giá trị ghi sổ 99,8 tỷ VND (sau dự phòng còn 92,7 tỷ), trong đó hàng tồn kho dở dang/vật tư chiếm 86,9 tỷ VND - tỷ trọng cực lớn. Dự phòng giảm giá hàng tồn kho tăng từ 6 tỷ lên 7 tỷ VND. Công ty có hoạt động sản xuất gạch với chu kỳ 12 tháng, nhưng lượng tồn kho dở dang cao bất thường so với doanh thu thuần 152 tỷ VND cho thấy hàng hóa có thể bị ứ đọng, chậm luân chuyển.', 8, 'Công ty Cổ phần VITALY đang trong tình trạng tài chính cực kỳ khó khăn. Năm 2023 công ty lỗ 28,5 tỷ VND (năm 2022 lỗ 7,7 tỷ), lỗ lũy kế 50,7 tỷ VND vượt quá 63% vốn điều lệ 80 tỷ. Doanh thu giảm 46% so với năm trước, giá vốn vượt doanh thu tạo lợi nhuận gộp âm 10,7 tỷ VND. Công ty phụ thuộc nặng nề vào hệ sinh thái Tổng Công ty VLXD Số 1 (70% doanh thu, 33% mua hàng). Tồn kho dở dang chiếm tỷ trọng rất lớn (86,9 tỷ/99,8 tỷ). Kiểm toán viên đưa ra nhấn mạnh về nghi ngờ khả năng hoạt động liên tục. Rủi ro đầu tư cực kỳ cao - cổ đông có thể mất toàn bộ vốn nếu công ty không vực dậy được hoạt động sản xuất kinh doanh.'),
('VTA_2022_consolidated', 'VTA', 2022, 'consolidated', 'Không có thông tin về giao dịch bên liên quan trong văn bản.', 'Không có thông tin chi tiết về nợ vay trong văn bản.', 'Không có thông tin về hàng tồn kho hoặc dự án xây dựng trong văn bản.', 4, 'Công ty đang ký hợp đồng kiểm toán với CPA Vietnam cho năm 2022, cho thấy sự tuân thủ quy định pháp luật về kiểm toán. Tuy nhiên, văn bản không chứa báo cáo tài chính chi tiết, nên không thể đánh giá sức khỏe tài chính, triển vọng đầu tư hay các rủi ro cụ thể.'),
('VTA_2021_consolidated', 'VTA', 2021, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm bán hàng, mua hàng, cho vay, nhận lãi vay và cổ tức. Các giao dịch này có giá trị lớn, đặc biệt là với Tổng Công ty VLXD số 1 - CTCP (cổ đông lớn) và các công ty cùng hệ thống. Điều này có thể tạo ra rủi ro về giá cả không công bằng hoặc chuyển lợi nhuận.', 'Công ty có nợ vay ngắn hạn và dài hạn đáng kể, với tổng nợ vay khoảng 42,27 tỷ VNĐ. Nợ ngắn hạn cao (37,015 tỷ VNĐ) tạo áp lực thanh toán. Tài sản thế chấp bao gồm bất động sản và máy móc thiết bị, nhưng tỷ lệ nợ trên tài sản cao.', 'Hàng tồn kho có dự phòng giảm giá 3,983 tỷ VNĐ cho thành phẩm, cho thấy nguy cơ tồn kho cũ hoặc mất giá. Tổng giá trị tồn kho cao (83,567 tỷ VNĐ), nhưng đã giảm so với đầu năm, có thể do tiêu thụ hoặc giảm giá.', 6, 'Công ty gặp khó khăn trong năm 2021 do ảnh hưởng của đại dịch COVID-19, dẫn đến doanh thu giảm và lỗ ròng 7,269 tỷ VNĐ. Tình hình tài chính căng thẳng với nợ vay cao, tồn kho có nguy cơ giảm giá, và giao dịch bên liên quan phức tạp. Ban lãnh đạo đang theo dõi rủi ro, nhưng triển vọng ngắn hạn còn thách thức.'),
('VTA_2020_consolidated', 'VTA', 2020, 'consolidated', 'Công ty có giao dịch mua bán lớn với Tổng Công ty Vật liệu Xây dựng Số 1 - CTCP (cổ đông lớn) và Công ty TNHH MTV Kinh doanh sản phẩm Fico (cùng hệ thống), cho thấy sự phụ thuộc đáng kể vào bên liên quan. Các giao dịch này có thể ảnh hưởng đến tính độc lập và giá cả giao dịch cần được xem xét.', 'Tổng nợ vay là 48.550.488.990 VND, trong đó nợ ngắn hạn chiếm phần lớn. Công ty có tài sản thế chấp (xe ô tô, máy móc) để đảm bảo khoản vay, nhưng áp lực trả nợ vẫn tồn tại do dòng tiền hoạt động kinh doanh giảm.', 'Hàng tồn kho có dự phòng giảm giá 3.183.175.785 VND, cho thấy một phần hàng tồn kho (thành phẩm) có thể bị lỗi thời hoặc kém phẩm chất. Điều này có thể ảnh hưởng đến giá trị tài sản và lợi nhuận.', 5, 'Công ty chịu ảnh hưởng tiêu cực từ dịch Covid-19, dẫn đến doanh thu và lợi nhuận giảm so với năm trước. Cơ cấu vốn có tỷ lệ nợ cao, nhưng có tài sản thế chấp đảm bảo. Giao dịch với bên liên quan phức tạp, đòi hỏi sự giám sát chặt chẽ. Công ty vẫn duy trì được lợi nhuận sau thuế, nhưng triển vọng phụ thuộc vào việc kiểm soát rủi ro và cải thiện hiệu quả kinh doanh.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTE_2023_consolidated', 'VTE', 2023, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với các bên liên quan, đặc biệt là Tập đoàn Bưu chính Viễn thông Việt Nam và các công ty con, chiếm tỷ trọng lớn trong doanh thu và mua hàng. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất, nhưng sự phụ thuộc vào bên liên quan có thể ảnh hưởng đến độc lập kinh doanh.', 'Nợ vay ngắn hạn giảm từ 82,7 tỷ VND xuống 59,4 tỷ VND, áp lực nợ vay giảm. Các khoản vay được đảm bảo bằng hàng hóa và phải thu, lãi suất biến động. Khả năng thanh toán từ dòng tiền kinh doanh.', 'Hàng tồn kho giảm từ 134,1 tỷ VND xuống 118,5 tỷ VND, không trích lập dự phòng. Bao gồm nguyên liệu và thành phẩm, rủi ro tồn kho thấp do không có dự phòng giảm giá.', 4, 'Sức khỏe tài chính có xu hướng giảm sút về lợi nhuận gộp và lợi nhuận sau thuế, nhưng nợ vay giảm. Doanh thu giảm, chi phí tài chính giảm. Triển vọng đầu tư trung bình, cần theo dõi hiệu quả kinh doanh và quản lý vốn lưu động.'),
('VTA_2016_consolidated', 'VTA', 2016, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là Công ty CP Bao bì và Khoáng sản số 1 (công ty liên kết) với doanh số mua bán vật tư lớn (hơn 20 tỷ năm nay). Các giao dịch được cho là thực hiện theo giá bán ra quy định chung và giá thị trường. Tuy nhiên, Công ty có khoản vay lớn từ cổ đông Tổng Công ty Vật liệu Xây dựng số 1 với lãi suất thấp (0.2%/tháng) và khoản phải trả dài hạn cho cổ đông này. Không có bằng chứng rõ ràng về giao dịch bất thường hay công ty sân sau.', 'Nợ vay ngắn hạn và dài hạn tổng cộng khoảng 46 tỷ VNĐ, giảm so với năm trước. Áp lực nợ vay vẫn còn do Công ty đang lỗ lũy kế. Phần lớn nợ vay có tài sản thế chấp là các máy móc, thiết bị sản xuất (dây chuyền, máy in gạch). Nợ vay từ Công ty Mua bán Nợ DATC (chuyển từ ngân hàng) có lãi suất cố định 7.5%/năm và được đảm bảo bằng tài sản cố định.', 'Hàng tồn kho chiếm tỷ trọng lớn (gần 66 tỷ, chủ yếu là thành phẩm gạch men ceramic), có trích lập dự phòng giảm giá khoảng 4 tỷ. Dự án xây dựng dở dang chủ yếu là chi phí mua sắm máy in đang lắp đặt, chưa có dấu hiệu ứ đọng lớn. Tồn kho thành phẩm tăng so với đầu năm có thể phản ánh áp lực tiêu thụ.', 4, 'Công ty hoạt động trong lĩnh vực sản xuất vật liệu xây dựng (gạch men) và kinh doanh bất động sản. Tình hình tài chính cải thiện so với năm trước, có lợi nhuận sau thuế (15.5 tỷ) và dòng tiền kinh doanh dương. Công ty đang dần khắc phục lỗ lũy kế. Tuy nhiên, vẫn còn phụ thuộc vào vay nợ từ các bên liên quan và ngân hàng, hàng tồn kho cao. Cổ đông nhà nước (Tổng Công ty VLXD số 1) chi phối 27% vốn. Công ty đã được kiểm toán và nhận ý kiến chấp nhận toàn phần, không có vấn đề going concern.'),
('VTA_2017_consolidated', 'VTA', 2017, 'consolidated', 'Có giao dịch với các bên liên quan bao gồm thanh toán lãi vay và mua bán hàng hóa. Giá bán và giá mua theo giá quy định và giá thị trường, không có dấu hiệu bất thường rõ ràng, nhưng cần theo dõi mối quan hệ và điều kiện giao dịch.', 'Áp lực nợ vay cao với tổng nợ ngắn hạn và dài hạn khoảng 47 tỷ VND, chiếm tỷ trọng lớn trong tài sản. Có nhiều khoản vay với lãi suất khác nhau, một số khoản vay ưu đãi lãi suất thấp. Tài sản thế chấp bao gồm nhà xưởng, máy móc và tiền gửi ngân hàng, nhưng khả năng thanh toán cần được đánh giá kỹ.', 'Hàng tồn kho tăng từ 65.7 tỷ lên 77.1 tỷ VND, dự phòng giảm giá tăng từ 4.06 tỷ lên 7.16 tỷ VND, cho thấy rủi ro tồn kho cao, có thể do sản phẩm chậm tiêu thụ hoặc giảm giá trị thị trường.', 6, 'Công ty hoạt động trong lĩnh vực sản xuất vật liệu xây dựng, có doanh thu và lợi nhuận nhưng giảm so với năm trước. Tồn kho tăng và dự phòng tăng đáng lo ngại. Nợ vay lớn, áp lực tài chính. Giao dịch với bên liên quan tồn tại nhưng không bất thường. Triển vọng đầu tư trung bình, cần cải thiện quản lý tồn kho và giảm đòn bẩy tài chính.'),
('VST_2025_consolidated', 'VST', 2025, 'consolidated', 'Công ty có phát sinh giao dịch với các bên liên quan bao gồm cho vay không lãi suất với công ty liên kết và ký quỹ hợp tác đầu tư. Các giao dịch này được ghi nhận theo giá trị ghi sổ, tuy nhiên cần đánh giá tính thị trường của các điều khoản vay không lãi suất.', 'Công ty đang đối mặt với áp lực nợ vay nghiêm trọng với nợ quá hạn thanh toán 190 tỷ VND và chi phí lãi vay phải trả 387 tỷ VND. Nợ ngắn hạn vượt quá tài sản ngắn hạn 623,48 tỷ VND cho thấy rủi ro thanh khoản cao. Công ty đã được giảm trừ nợ 304 tỷ VND trong năm 2025 nhưng vẫn còn gánh nặng nợ lớn.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ với giá trị 39 tỷ VND, không có dự phòng giảm giá. Dự án sửa chữa lớn tàu HD Sun trị giá 1,69 tỷ VND đang dở dang. Rủi ro tồn kho không cao.', 7, 'Công ty đang trong tình trạng tài chính yếu kém với lỗ lũy kế lớn, vốn chủ sở hữu âm và nợ quá hạn thanh toán. Tuy nhiên, trong năm 2025 công ty đã đạt được lợi nhuận sau thuế 247 tỷ VND nhờ vào thu nhập từ việc giảm trừ nợ phải trả 304 tỷ VND. Công ty đang nỗ lực tái cơ cấu tài chính và được miễn giảm nợ. Triển vọng phụ thuộc vào khả năng tái cơ cấu và cải thiện hoạt động kinh doanh.'),
('VTA_2015_consolidated', 'VTA', 2015, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan, bao gồm mua bán hàng hóa, vay nợ, và phải thu/phải trả. Các giao dịch này có thể tiềm ẩn rủi ro về giá cả không công bằng hoặc lợi ích chồng chéo, nhưng không có bằng chứng rõ ràng về giao dịch bất thường trong báo cáo.', 'Áp lực nợ vay cao với tổng nợ phải trả chiếm hơn 80% tổng nguồn vốn. Công ty có nhiều khoản vay với lãi suất cao từ các bên liên quan và ngân hàng, đòi hỏi dòng tiền ổn định để thanh toán. Tài sản thế chấp bao gồm dây chuyền sản xuất và dự án đầu tư.', 'Hàng tồn kho có dự phòng giảm giá lớn, đặc biệt là nguyên liệu và thành phẩm, cho thấy rủi ro giảm giá trị do biến động thị trường hoặc hàng hóa lỗi thời. Công ty cần quản lý tồn kho chặt chẽ.', 6, 'Công ty Vitaly có tình hình tài cải thiện trong năm 2015 với lợi nhuận tăng trưởng, nhưng vẫn chịu áp lực nợ vay lớn và rủi ro từ giao dịch liên quan. Tỷ suất sinh lời cải thiện, nhưng khả năng thanh toán ngắn hạn thấp. Triển vọng trung bình, phụ thuộc vào quản lý nợ và hiệu quả hoạt động.'),
('VST_2024_consolidated', 'VST', 2024, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao cho người quản lý chủ chốt, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay rất lớn với tổng nợ phải trả vượt xa tài sản, nợ vay quá hạn thanh toán 218,72 tỷ VND, lãi vay phải trả quá hạn 584,33 tỷ VND. Công ty đã được xóa một phần nợ lãi nhưng vẫn trong tình trạng mất khả năng thanh toán, tài sản thế chấp chủ yếu là tàu biển đã cũ.', 'Hàng tồn kho giảm nhẹ và không có dự phòng giảm giá, nhưng giá trị không đáng kể so với quy mô nợ. Không có dự án xây dựng dở dang rủi ro.', 9, 'Công ty đang trong tình trạng tài chính cực kỳ khó khăn với lỗ lũy kế lớn, vốn chủ sở hữu âm, nợ ngắn hạn vượt tài sản ngắn hạn. Báo cáo kiểm toán ngoại trừ do nghi ngờ về khả năng hoạt động liên tục. Tuy nhiên, Công ty có kế hoạch tái cơ cấu tài chính, được xóa nợ lãi và đang tìm kiếm nguồn vốn. Triển vọng đầu tư rất rủi ro.'),
('VST_2023_parent', 'VST', 2023, 'parent', 'Công ty có giao dịch lớn với các công ty con (SCCM và Hải Đăng) bao gồm mua hàng hóa dịch vụ 6,8 tỷ đồng, doanh thu dịch vụ 12,8 tỷ đồng và lợi nhuận phân phối 16,3 tỷ đồng. Có khoản cho mượn không lãi suất 2 tỷ đồng từ cá nhân bà Dương Thanh Thủy. Các khoản phải thu từ công ty con lên tới 38,5 tỷ đồng (ngắn hạn) và 15 tỷ đồng (dài hạn). Tổng thể giao dịch với bên liên quan chiếm tỷ trọng đáng kể nhưng chưa có dấu hiệu bất thường nghiêm trọng.', 'Áp lực nợ vay cực kỳ nghiêm trọng: Tổng nợ vay 479 tỷ đồng với 319 tỷ đồng là nợ ngắn hạn/quá hạn thanh toán. Nợ ngắn hạn vượt tài sản ngắn hạn 1.008 tỷ đồng. Chi phí lãi vay phải trả quá hạn lên tới 749 tỷ đồng. Công ty đã đạt thỏa thuận xóa nợ gốc 86 tỷ đồng và nợ lãi 484,8 tỷ đồng với DATC. Dự kiến được miễn giảm thêm 530 tỷ đồng trong 2024-2025. Đội tàu 5 chiếc đã hết khấu hao nhưng có giá trị thị trường đủ khả năng trả nợ.', 'Hàng tồn kho giảm từ 39 tỷ xuống 27,9 tỷ đồng, chủ yếu là nguyên liệu vật liệu và công cụ dụng cụ phục vụ sửa chữa tàu. Không có dự phòng giảm giá tồn kho. Dự án xây dựng dở dang chỉ 626 triệu đồng (dự án văn phòng nhỏ), rủi ro ứ đọng thấp.', 8, 'Công ty VST đang trong tình trạng tài chính đặc biệt khó khăn với vốn chủ sở hữu âm 908 tỷ đồng, lỗ lũy kế 1.595 tỷ đồng. Tuy nhiên năm 2023 Công ty đã ghi nhận lợi nhuận sau thuế 564 tỷ đồng nhờ khoản thu nhập từ thanh lý tàu VTC Sun và xóa nợ 571 tỷ đồng. Doanh thu giảm 64,7% do giá cước vận tải biển giảm mạnh. Công ty đã ký kết nhiều thỏa thuận tái cơ cấu tài chính với DATC và các ngân hàng. Rủi ro chính là khả năng thanh toán nợ đến hạn và phụ thuộc vào kết quả tái cơ cấu tài chính. Điểm rủi ro quản trị cao do cấu trúc sở hữu phức tạp, giao dịch bên liên quan lớn và tình hình tài chính suy yếu.'),
('VST_2023_consolidated', 'VST', 2023, 'consolidated', 'Giao dịch chủ yếu là lương thưởng cho ban lãnh đạo, không có giao dịch bất thường đáng kể với các bên liên quan.', 'Nợ vay cao, nợ ngắn hạn vượt tài sản ngắn hạn, lỗ lũy kế lớn, áp lực thanh toán nợ rất cao. Nhiều khoản vay đã quá hạn, tài sản thế chấp chủ yếu là tàu biển đã khấu hao.', 'Hàng tồn kho là nguyên vật liệu và công cụ dụng cụ, không có dự phòng, rủi ro giảm giá thấp. Dự án xây dựng dở dang có giá trị nhỏ, không đáng lo ngại.', 8, 'Công ty đang trong giai đoạn tái cơ cấu tài chính với lỗ lũy kế lớn, vốn chủ sở hữu âm. Tuy nhiên, trong năm 2023, Công ty đã có lợi nhuận từ bán tàu và giảm trừ nợ, giúp cải thiện kết quả kinh doanh. Khả năng hoạt động liên tục còn nhiều nghi ngờ nhưng Công ty có kế hoạch tái cơ cấu với các ngân hàng. Triển vọng đầu tư rủi ro cao.'),
('VST_2021_parent', 'VST', 2021, 'parent', 'Giao dịch với bên liên quan chủ yếu với công ty con, bao gồm mua hàng hóa dịch vụ, lợi nhuận được phân phối và cung cấp dịch vụ. Giá trị giao dịch lớn nhưng chưa có dấu hiệu bất thường về giá hay điều kiện giao dịch.', 'Rủi ro nợ vay rất cao. Nợ ngắn hạn vượt quá tài sản ngắn hạn, lỗ lũy kế lớn, vốn chủ sở hữu âm. Nhiều khoản vay đã quá hạn thanh toán, Công ty đang bị ngân hàng kiện ra tòa để đòi nợ. Áp lực thanh toán nợ trong ngắn hạn rất lớn, nguy cơ mất khả năng thanh toán.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có dự phòng giảm giá. Các dự án xây dựng dở dang bao gồm sửa chữa tàu và xây dựng văn phòng, quy mô nhỏ và không có dấu hiệu ứ đọng lớn.', 8, 'Tình hình tài chính của Công ty rất nghiêm trọng: nợ vượt quá tài sản, lỗ lũy kế lớn, vốn chủ sở hữu âm, dòng tiền hoạt động kinh doanh không đủ bù đắp dòng tiền đầu tư và tài chính. Công ty đang đối mặt với nhiều vụ kiện từ ngân hàng và nguy cơ mất khả năng thanh toán. Mặc dù doanh thu tăng trưởng mạnh trong năm 2021 do giá cước vận tải biển tăng, nhưng cơ cấu tài chính yếu kém đặt ra thách thức lớn cho hoạt động liên tục. Triển vọng đầu tư rất rủi ro.'),
('VST_2022_consolidated', 'VST', 2022, 'consolidated', 'Công ty có các giao dịch với công ty con (SCCM và Hải Đăng) bao gồm mua bán hàng hóa dịch vụ, cung cấp dịch vụ, cho vay không lãi suất từ cá nhân. Các giao dịch này có quy mô lớn, đặc biệt khoản phải thu từ Công ty TNHH Quản lý tàu biển Hải Đăng lên đến 60,7 tỷ đồng. Tuy nhiên, chưa phát hiện dấu hiệu giao dịch bất thường hay giá chuyển nhượng không hợp lý.', 'Công ty đang đối mặt với áp lực nợ vay rất lớn. Tổng nợ vay 724,6 tỷ đồng, trong đó nợ ngắn hạn 398,9 tỷ đồng và nợ dài hạn 325,7 tỷ đồng. Nhiều khoản vay đã quá hạn thanh toán và đang trong quá trình tái cơ cấu với Công ty TNHH Mua bán nợ Việt Nam (DATC). Chi phí lãi vay phải trả cho các khoản vay quá hạn là 1.204 tỷ đồng. Công ty có lỗ lũy kế 2.159 tỷ đồng và vốn chủ sở hữu âm 1.514 tỷ đồng, cho thấy nguy cơ mất khả năng thanh toán. Tài sản thế chấp chủ yếu là các tàu biển.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và công cụ dụng cụ với tổng giá trị 39 tỷ đồng, không có dự phòng giảm giá. Các dự án xây dựng dở dang có giá trị nhỏ (1 tỷ đồng) và đang trong giai đoạn đầu tư. Rủi ro tồn kho thấp.', 7, 'Công ty ghi nhận lợi nhuận sau thuế 211,8 tỷ đồng trong năm 2022 nhờ giá cước vận tải biển tăng đột biến, nhưng vẫn lỗ lũy kế 2.159 tỷ đồng. Nợ vay quá hạn lớn và chi phí lãi vay cao là thách thức lớn. Công ty đang thực hiện tái cơ cấu tài chính thông qua hoán đổi nợ thành vốn cổ phần. Tuy nhiên, triển vọng đầu tư vẫn rủi ro cao do cơ cấu tài chính yếu kém và khả năng thanh khoản thấp.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VST_2021_consolidated', 'VST', 2021, 'consolidated', 'Công ty có giao dịch với các bên liên quan chủ yếu là thu nhập của ban lãnh đạo, không phát hiện giao dịch bất thường. Tuy nhiên, công ty có khoản ký quỹ cho hợp đồng hợp tác đầu tư với Công ty TNHH Trung Thủy Lancaster và khoản mượn tiền lãi suất 0% từ cá nhân, cần theo dõi.', 'Rủi ro nợ vay rất cao. Nợ ngắn hạn vượt quá tài sản ngắn hạn, lỗ lũy kế lớn, vốn chủ sở hữu âm. Các khoản nợ vay quá hạn thanh toán lên tới 824 tỷ đồng, chi phí lãi vay phải trả cho các khoản vay quá hạn là 1,105 tỷ đồng. Công ty đang đối mặt với các vụ kiện từ ngân hàng và có nguy cơ mất khả năng thanh toán.', 'Rủi ro tồn kho ở mức trung bình. Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có dự phòng giảm giá. Các dự án xây dựng dở dang có thể bị ứ đọng do vướng mắc thủ tục.', 8, 'Tình hình tài chính của công ty rất khó khăn với lỗ lũy kế lớn, vốn chủ sở hữu âm và nợ vay quá hạn cao. Doanh thu năm 2021 tăng 19.39% so với năm 2020 nhờ giá cước tàu hàng khô tăng, nhưng công ty vẫn lỗ ròng. Khả năng hoạt động liên tục bị nghi ngờ nặng nề. Công ty cần tái cơ cấu tài chính, đàm phán với ngân hàng để xử lý nợ quá hạn và tìm kiếm nguồn vốn mới để duy trì hoạt động.'),
('VST_2020_consolidated', 'VST', 2020, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với công ty con và công ty liên kết, bao gồm mua hàng hóa dịch vụ lớn và phân phối lợi nhuận từ công ty con. Có khoản phải thu lớn từ công ty con (15,2 tỷ VND) và phải trả cho các bên liên quan. Ngoài ra, có khoản mượn không lãi suất từ cá nhân liên quan. Các giao dịch này có thể không đảm bảo tính công bằng và minh bạch.', 'Nợ vay quá hạn thanh toán lên tới 793 tỷ VND, nợ ngắn hạn vượt tài sản ngắn hạn 2.133 tỷ VND, lỗ lũy kế 2.361 tỷ VND, vốn chủ sở hữu âm 1.716 tỷ VND. Công ty đang bị kiện bởi nhiều ngân hàng. Rủi ro thanh khoản cực kỳ cao, nguy cơ phá sản.', 'Hàng tồn kho chủ yếu là nguyên liệu vật liệu và công cụ dụng cụ, không có dự phòng giảm giá. Dự án xây dựng dở dang có giá trị nhỏ nhưng chưa triển khai do vướng mắc thủ tục, có thể không tạo ra giá trị.', 9, 'Công ty đang trong tình trạng tài chính rất xấu, với lỗ lũy kế lớn, nợ quá hạn cao, vốn chủ sở hữu âm. Doanh thu giảm mạnh do ảnh hưởng của COVID-19 và sự cố tàu. Công ty đang tìm kiếm tái cơ cấu tài chính nhưng rủi ro phá sản là rất cao. Khả năng hoạt động liên tục bị nghi ngờ.'),
('VST_2019_consolidated', 'VST', 2019, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là mua hàng hóa dịch vụ từ công ty liên kết PDIMEX JSC và các khoản phải trả liên quan. Số tiền không quá lớn so với tổng tài sản, nhưng công ty đang gặp khó khăn tài chính, cần theo dõi thanh toán cho bên liên quan.', 'Rủi ro nợ vay rất cao. Công ty có tổng nợ vay hơn 1,300 tỷ VND, trong đó nợ quá hạn thanh toán lên đến 736 tỷ VND. Nợ ngắn hạn vượt quá tài sản ngắn hạn, vốn chủ sở hữu âm, cho thấy nguy cơ mất khả năng thanh toán.', 'Hàng tồn kho chủ yếu là nguyên liệu và công cụ dụng cụ, không có dự phòng giảm giá. Dự án xây dựng cơ bản dở dang đã tồn tại nhiều năm, chưa triển khai do khó khăn tài chính, có thể không mang lại giá trị.', 8, 'Công ty đang trong tình trạng tài chính rất khó khăn với lỗ lũy kế 2,053 tỷ VND, vốn chủ sở hữu âm 1,429 tỷ VND. Nợ vay quá hạn lớn, nguy cơ kiện tụng từ ngân hàng. Ban lãnh đạo đang tìm cách tái cơ cấu tài chính, nhưng triển vọng đầu tư rất rủi ro.'),
('VST_2018_consolidated', 'VST', 2018, 'consolidated', 'Giao dịch với công ty liên kết PDIMEX JSC bao gồm mua hàng hóa và khoản phải trả, trong đó có khoản lãi chậm trả 1,05 tỷ đồng. Không phát hiện giao dịch bất thường đáng ngờ như cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Rủi ro nợ vay rất cao. Tổng nợ vay ngắn hạn và dài hạn khoảng 1.376 tỷ đồng, hầu hết đã quá hạn thanh toán và bị ngân hàng kiện ra tòa. Các khoản vay được đảm bảo bằng tàu biển, trong đó tàu VTC Ocean đã bị ngân hàng tạm giữ. Công ty đang đàm phán tái cơ cấu nợ nhưng chưa có thỏa thuận thay thế.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có hàng ứ đọng hay mất phẩm chất. Chi phí xây dựng dở dang liên quan đến dự án đất đai có tranh chấp pháp lý, có thể ảnh hưởng đến giá trị tài sản.', 7, 'Tập đoàn đang trong tình trạng tài chính rất khó khăn với khoản lỗ lũy kế lớn (1.780 tỷ đồng), nợ ngắn hạn vượt tài sản ngắn hạn gần 1.900 tỷ đồng, và hầu hết nợ vay đã quá hạn. Dòng tiền kinh doanh vẫn dương (27 tỷ đồng năm 2018) và có cam kết hỗ trợ từ cổ đông lớn Tổng Công ty Hàng hải Việt Nam. Tuy nhiên, triển vọng đầu tư rủi ro rất cao do nguy cơ mất khả năng thanh toán và các tranh chấp pháp lý tiềm tàng.'),
('VST_2015_parent', 'VST', 2015, 'parent', 'Doanh nghiệp có công ty con (Công ty TNHH MTV Sửa chữa tàu biển Phương Nam) và công ty liên kết (PDIMEX JSC). Đã thoái vốn một phần tại PDIMEX từ 56,67% xuống 26,46%. Các giao dịch nội bộ với chi nhánh không có dấu hiệu bất thường lớn nhưng cần theo dõi.', 'Áp lực nợ vay rất lớn với tổng nợ vay gốc khoảng 1.535 tỷ đồng, chiếm phần lớn tổng tài sản. Công ty đã bàn giao tàu VTC Tiger và VTC Ace cho Ngân hàng TMCP Hàng hải Việt Nam để xử lý nợ. Nợ ngắn hạn và dài hạn đều cao, khả năng thanh toán thấp, doanh nghiệp đang trong quá trình tái cơ cấu.', 'Hàng tồn kho giảm mạnh từ 92,9 tỷ xuống 56,2 tỷ đồng, không trích lập dự phòng giảm giá. Dự án xây dựng cơ bản dở dang tăng nhẹ từ 0,8 tỷ lên 2,5 tỷ đồng nhưng quy mô nhỏ, rủi ro không đáng kể.', 7, 'Doanh nghiệp đang trong giai đoạn khó khăn tài chính nghiêm trọng, lỗ lũy kế lớn, nợ vay cao, buộc phải tái cơ cấu mạnh. Các biện pháp tái cơ cấu đang được triển khai nhưng hiệu quả chưa rõ ràng. Triển vọng đầu tư không rõ ràng, rủi ro rất cao.'),
('VST_2015_consolidated', 'VST', 2015, 'consolidated', 'Không có giao dịch bất thường với các bên liên quan. Công ty có giao dịch nội bộ với công ty con và liên kết nhưng không đáng kể.', 'Công ty có nợ vay lớn với tổng nợ phải trả vượt quá tài sản. Áp lực nợ vay cao, nợ ngắn hạn và dài hạn đều lớn. Công ty đã bàn giao tàu cho ngân hàng để xử lý nợ.', 'Hàng tồn kho giảm mạnh từ 99 tỷ xuống 56 tỷ, không trích lập dự phòng, cho thấy quản lý tồn kho hiệu quả hoặc rủi ro thấp.', 7, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế lớn và vốn chủ sở hữu âm. Công ty đang triển khai các biện pháp tái cơ cấu, thanh lý tài sản và khẳng định hoạt động liên tục. Triển vọng đầu tư rủi ro cao.'),
('VSN_2025_consolidated', 'VSN', 2025, 'consolidated', 'Công ty có giao dịch đáng kể với công ty mẹ và các đơn vị trực thuộc trong hệ thống Satra, bao gồm mua bán hàng hóa dịch vụ và các khoản phải thu phải trả. Tuy nhiên, tỷ trọng giao dịch với bên liên quan trên tổng doanh thu và chi phí không quá lớn và không có dấu hiệu giao dịch bất thường rõ rệt về lãi suất hay điều kiện.', 'Áp lực nợ vay thấp, tỷ lệ nợ vay/tổng tài sản chỉ khoảng 6.7%. Nợ vay chủ yếu là ngắn hạn, giảm mạnh so với đầu năm. Công ty có tài sản thế chấp là máy móc thiết bị cho một số khoản vay dài hạn. Khả năng thanh toán nợ tốt.', 'Hàng tồn kho tăng nhẹ so với đầu năm, chủ yếu tăng ở thành phẩm và nguyên liệu. Dự phòng giảm giá hàng tồn kho không đáng kể (1.2 tỷ VND). Dự án xây dựng cơ bản dở dang (15 tỷ VND) liên quan đến di dời nhà máy, tiến triển chậm có thể ảnh hưởng đến hoạt động sản xuất tương lai.', 3, 'Công ty VIỆT NAM KỸ NGHỆ SỨC SẢN (VSN) có kết quả kinh doanh giảm trong năm 2025 với doanh thu thuần giảm 6.9% và lợi nhuận sau thuế giảm 26.1% so với năm trước. Công ty có cơ cấu tài chính lành mạnh với tỷ lệ nợ vay/tổng tài sản thấp, khả năng thanh toán tốt. Dòng tiền hoạt động kinh doanh âm do tăng tồn kho và giảm phải trả. Dự án đầu tư xây dựng nhà máy mới có thể cải thiện năng lực sản xuất trong tương lai. Rủi ro quản trị ở mức thấp.'),
('VSN_2022_consolidated', 'VSN', 2022, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa và dịch vụ với các bên liên quan là công ty mẹ và các công ty thành viên thuộc tập đoàn. Các giao dịch này được thực hiện theo giá thị trường và không có dấu hiệu bất thường, tuy nhiên vẫn cần theo dõi để đảm bảo tính minh bạch.', 'Tổng nợ vay giảm mạnh so với năm trước, áp lực nợ vay thấp. Công ty có tài sản thế chấp là máy móc thiết bị cho các khoản vay dài hạn, đảm bảo an toàn cho các khoản vay.', 'Hàng tồn kho chủ yếu là thành phẩm và nguyên vật liệu, có dự phòng giảm giá. Dự án xây dựng dở dang không có dấu hiệu ứ đọng, đang trong quá trình triển khai.', 3, 'Tình hình tài chính của Công ty ổn định, doanh thu giảm nhẹ nhưng lợi nhuận sau thuế vẫn ở mức cao. Công ty có tỷ lệ nợ vay thấp, thanh khoản tốt và quản trị rủi ro hiệu quả. Triển vọng đầu tư tích cực.'),
('VSN_2023_consolidated', 'VSN', 2023, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là giao dịch thương mại thông thường với công ty mẹ và các đơn vị trực thuộc, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn được ghi nhận.', 'Nợ vay chủ yếu từ ngân hàng với lãi suất thay đổi, tài sản thế chấp là máy móc thiết bị. Tỷ lệ nợ trên tài sản thấp, áp lực nợ vay không cao và khả năng thanh toán được đảm bảo.', 'Hàng tồn kho có dự phòng giảm giá nhưng tỷ trọng nhỏ, chủ yếu là thành phẩm và nguyên vật liệu. Các dự án xây dựng dở dang không bị ứ đọng, rủi ro tồn kho thấp.', 2, 'Công ty có tình hình tài chính ổn định với biên lợi nhuận gộp tốt, nợ vay kiểm soát hiệu quả, và quản trị công ty minh bạch. Triển vọng đầu tư tích cực trong ngành thực phẩm.'),
('VSN_2024_consolidated', 'VSN', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán hàng hóa với công ty mẹ và các đơn vị trực thuộc, với giá trị lớn nhưng theo giá thị trường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay ở mức vừa phải, với các khoản vay ngắn hạn không có tài sản thế chấp và vay dài hạn có thế chấp bằng máy móc, thiết bị. Công ty có đủ khả năng thanh toán từ hoạt động kinh doanh.', 'Hàng tồn kho giảm so với năm trước, với dự phòng giảm giá được trích lập, cho thấy quản lý tồn kho hiệu quả và không có ứ đọng lớn.', 3, 'Sức khỏe tài chính ổn định với lợi nhuận sau thuế tăng nhẹ, triển vọng đầu tư tích cực do vị thế thị trường mạnh trong ngành thực phẩm và quản lý tài chính thận trọng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSN_2021_consolidated', 'VSN', 2021, 'consolidated', 'Công ty có giao dịch với bên liên quan là công ty mẹ Tổng Công ty Thương mại Sài Gòn - TNHH MTV, bao gồm bán hàng và mua hàng hóa. Các giao dịch này dường như theo giá thị trường và không có dấu hiệu bất thường. Chi phí cho nhân sự quản lý chủ chốt được tiết lộ đầy đủ, không có giao dịch đáng ngờ.', 'Công ty có nợ vay ngắn hạn và dài hạn từ các ngân hàng. Không có khoản vay quá hạn. Nợ ngắn hạn chủ yếu không có tài sản thế chấp, nợ dài hạn có tài sản thế chấp là máy móc thiết bị. Áp lực nợ ở mức trung bình, công ty đánh giá có khả năng thanh toán đầy đủ khi đến hạn.', 'Hàng tồn kho bao gồm thành phẩm và nguyên vật liệu, với dự phòng giảm giá hàng tồn kho tỷ lệ nhỏ (khoảng 0.15% giá trị). Các dự án xây dựng dở dang có tiến độ chậm, có thể bị ảnh hưởng bởi tình hình Covid-19 và thủ tục pháp lý.', 3, 'Tình hình tài chính của công ty ổn định với tỷ suất lợi nhuận gộp khoảng 23.2%. Nợ vay được kiểm soát, dòng tiền hoạt động kinh doanh dương. Tuy nhiên, doanh thu giảm so với năm trước do ảnh hưởng của đại dịch Covid-19. Công ty có cam kết vốn lớn cho dự án di đời nhà máy, triển vọng phụ thuộc vào kiểm soát đại dịch và nhu cầu thị trường.'),
('VSN_2019_consolidated', 'VSN', 2019, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là bán hàng và mua hàng hóa với công ty mẹ Tổng Công ty Thương mại Sài Gòn – TNHH MTV, không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch giá lớn. Giao dịch với nhân sự quản lý chủ chốt ở mức hợp lý.', 'Nợ vay chủ yếu từ ngân hàng với tài sản thế chấp là máy móc thiết bị. Áp lực nợ ngắn hạn ở mức trung bình với tỷ lệ nợ ngắn hạn cao, nhưng công ty có khả năng thanh toán tốt dựa trên dòng tiền hoạt động kinh doanh dương.', 'Hàng tồn kho có dự phòng giảm giá nhưng tỷ lệ nhỏ so với giá trị. Các dự án xây dựng dở dang đang triển khai, không có dấu hiệu ứ đọng lớn.', 3, 'Công ty có sức khỏe tài chính ổn định với tăng trưởng doanh thu và lợi nhuận. Tỷ suất lợi nhuận gộp cải thiện, dòng tiền hoạt động kinh doanh dương. Nợ vay được kiểm soát, tài sản thế chấp rõ ràng. Rủi ro quản trị thấp do giao dịch bên liên quan minh bạch và kiểm toán đạt ý kiến chấp nhận toàn phần.'),
('VSN_2020_consolidated', 'VSN', 2020, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với công ty mẹ và các bên liên quan, bao gồm bán hàng, mua hàng và cho thuê. Các giao dịch này có vẻ theo giá thị trường nhưng cần giám sát để tránh xung đột lợi ích và đảm bảo tính công bằng.', 'Nợ vay ngắn hạn tăng mạnh từ 196 tỷ lên 342 tỷ VNĐ, áp lực trả nợ cao. Nợ dài hạn ổn định với lãi suất cố định và có tài sản thế chấp. Công ty có khả năng thanh toán nhưng cần quản lý dòng tiền chặt chẽ.', 'Hàng tồn kho ở mức ổn định, dự phòng giảm giá tăng nhẹ cho thấy rủi ro hàng lỗi thời. Các dự án xây dựng dở dang tiến triển chậm, có thể ảnh hưởng đến dòng tiền trong tương lai và cần theo dõi tiến độ.', 6, 'Công ty có tình hình tài chính ổn định với doanh thu tăng trưởng nhẹ nhưng lợi nhuận giảm do chi phí tăng. Nợ vay tăng nhưng được kiểm soát. Triển vọng trung bình, cần cải thiện quản lý dòng vốn và giảm rủi ro từ các giao dịch bên liên quan.'),
('VSN_2018_consolidated', 'VSN', 2018, 'consolidated', 'Công ty có giao dịch mua bán với công ty mẹ - Tổng Công ty Thương mại Sài Gòn - TNHH MTV. Giá trị giao dịch mua bán lớn nhưng không có thông tin về lãi suất bất thường hay chênh lệch giá đáng kể. Rủi ro liên quan đến bên liên quan ở mức trung bình do tính minh bạch trong mối quan hệ mẹ-con và giao dịch diễn ra thường xuyên.', 'Công ty có nợ vay ngắn hạn và dài hạn với ngân hàng, lãi suất dao động từ 5.2% đến 9.3%/năm. Tài sản thế chấp chủ yếu là máy móc, thiết bị. Áp lực nợ vay ở mức vừa phải do công ty có doanh thu ổn định và dòng tiền từ hoạt động tài chính âm nhưng được kiểm soát.', 'Hàng tồn kho có giá trị lớn, chủ yếu là thành phẩm và nguyên liệu. Công ty đã trích lập dự phòng giảm giá hàng tồn kho, nhưng số dư dự phòng giảm so với năm trước cho thấy khả năng quản lý tồn kho hiệu quả. Rủi ro tồn kho thấp do sản phẩm thực phẩm có chu kỳ nhanh và nhu cầu ổn định.', 5, 'Công ty hoạt động trong ngành thực phẩm với doanh thu thuần tăng trưởng 14.5% so với năm trước, nhưng lợi nhuận gộp giảm nhẹ do giá vốn tăng. Nợ vay được kiểm soát với lãi suất hợp lý, tài sản thế chấp rõ ràng. Dòng tiền từ hoạt động kinh doanh âm do chi phí tăng, nhưng khả năng thanh toán vẫn ổn định. Triển vọng đầu tư trung bình, phù hợp với ngành hàng tiêu dùng thiết yếu.'),
('VSN_2017_consolidated', 'VSN', 2017, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán hàng hóa thông thường với Tổng Công ty Thương mại Sài Gòn - TNHH MTV (cổ đông lớn nhất), không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn và dài hạn với lãi suất thị trường, có tài sản thế chấp và không có nợ quá hạn. Áp lực nợ vay ở mức kiểm soát được.', 'Hàng tồn kho có trích lập dự phòng giảm giá nhưng mức dự phòng không đáng kể so với giá trị tồn kho, chủ yếu là nguyên liệu và thành phẩm.', 3, 'Công ty hoạt động kinh doanh hiệu quả với doanh thu và lợi nhuận tăng trưởng, biên lợi nhuận gộp ở mức tốt. Cơ cấu vốn hợp lý, nợ vay có bảo đảm và không có rủi ro thanh toán. Đánh giá tổng thể, tình hình tài chính lành mạnh và triển vọng đầu tư tích cực.'),
('VSN_2016_consolidated', 'VSN', 2016, 'consolidated', 'Giao dịch chủ yếu với công ty mẹ Tổng Công ty Thương mại Sài Gòn – TNHH MTV, bao gồm mua bán hàng hóa và phân phối lợi nhuận. Các giao dịch này không có lãi suất và thời hạn thanh toán ngắn, không có dấu hiệu bất thường đáng kể.', 'Nợ vay ngắn hạn tăng mạnh từ 110.499.498.093 VND lên 214.331.478.628 VND, chủ yếu từ ngân hàng với lãi suất dao động 4,30% - 7,00%. Một số khoản vay được đảm bảo bằng tài sản cố định hữu hình và vô hình. Áp lực nợ vay cao nhưng tài sản thế chấp đủ để đảm bảo.', 'Hàng tồn kho tăng từ 340.097.784.816 VND lên 452.525.036.233 VND, chủ yếu là thành phẩm và nguyên vật liệu. Có dự phòng giảm giá hàng tồn kho 192.754.415 VND cho thành phẩm. Xây dựng cơ bản dở dang tăng với các dự án đang triển khai, chưa có dấu hiệu ứ đọng.', 3, 'Công ty hoạt động trong lĩnh vực thực phẩm chế biến với doanh thu thuần ổn định khoảng 1.838 tỷ VND trong kỳ. Lợi nhuận gộp đạt 401 tỷ VND, tỷ suất lợi nhuận gộp khoảng 21,8%. Tuy nhiên, chi phí quản lý doanh nghiệp tăng đáng kể do phân bổ lợi thế thương mại. Nợ vay tăng, đặc biệt là ngắn hạn, nhưng vẫn trong tầm kiểm soát. Công ty có mối quan hệ chặt chẽ với công ty mẹ, nhưng không có rủi ro quản trị nghiêm trọng. Triển vọng trung bình, cần theo dõi áp lực nợ và quản lý hàng tồn kho.'),
('VSN_2015_consolidated', 'VSN', 2015, 'consolidated', 'Giao dịch với công ty mẹ là lớn (mua hàng 671 tỷ, bán hàng 266 tỷ), nhưng là giao dịch thương mại thông thường trong chuỗi cung ứng. Không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay ngắn hạn giảm mạnh, nợ dài hạn tăng với tài sản thế chấp đầy đủ (máy móc, đất đai). Áp lực trả nợ trung bình, lãi suất linh hoạt theo thỏa thuận.', 'Tồn kho thành phẩm và nguyên liệu lớn (399 tỷ), cùng nhiều dự án xây dựng dở dang (25 tỷ). Cần theo dõi tiến độ các dự án để tránh ứ đọng vốn.', 6, 'Công ty có lợi nhuận gộp cao (801 tỷ), chi phí khấu hao 17.7 tỷ. Dòng tiền hoạt động kinh doanh dương (135 tỷ). Tuy nhiên, cần quản lý chặt chẽ nợ vay và tiến độ các dự án đầu tư. Triển vọng trung bình, phù hợp với ngành thực phẩm.'),
('VSM_2024_consolidated', 'VSM', 2024, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là công ty mẹ và các công ty cùng hệ thống. Các giao dịch chủ yếu là cung cấp và sử dụng dịch vụ logistics, trả nợ vay và cổ tức. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất hợp lý.', 'Áp lực nợ vay thấp. Công ty đã trả toàn bộ nợ vay (cả ngắn hạn và dài hạn) trong năm 2024, giảm mạnh từ 13,26 tỷ VND đầu năm xuống 0 cuối năm. Công ty không có tài sản thế chấp cho vay và nợ thuê tài chính.', 'Rủi ro tồn kho ở mức trung bình. Hàng tồn kho (nguyên liệu, vật liệu) tăng mạnh từ 1,13 tỷ lên 3,09 tỷ VND, nhưng không có dự phòng giảm giá và công ty khẳng định không có hàng tồn kho ứ đọng, kém phẩm chất hay dùng để thế chấp.', 4, 'Công ty Container Miền Trung có kết quả kinh doanh tăng trưởng tốt năm 2024 với doanh thu thuần tăng 11,5% và lợi nhuận sau thuế tăng 5%. Công ty đã chủ động giảm đòn bẩy tài chính bằng cách trả toàn bộ nợ vay. Dòng tiền từ hoạt động kinh doanh mạnh. Hàng tồn kho tăng cần được theo dõi. Quản trị công ty ở mức trung bình với các giao dịch bên liên quan minh bạch.'),
('VSM_2025_consolidated', 'VSM', 2025, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là công ty con và công ty mẹ. Các giao dịch cho vay được thực hiện theo hợp đồng với lãi suất công khai, không có dấu hiệu bất thường. Tuy nhiên, mức độ giao dịch lớn có thể ảnh hưởng đến tính độc lập.', 'Công ty không có nợ vay tài chính, nợ phải trả chủ yếu là thương mại và ngắn hạn, không có áp lực thanh toán lớn.', 'Hàng tồn kho chủ yếu là nguyên liệu vật liệu, không có dự phòng giảm giá. Chi phí xây dựng dở dang là phần mềm quản lý, không có rủi ro ứ đọng.', 3, 'Công ty hoạt động ổn định trong lĩnh vực logistics, có lợi nhuận tốt, không có nợ vay và dòng tiền mạnh. Tuy nhiên, doanh thu tập trung vào dịch vụ cảng và vận tải, chịu ảnh hưởng của chu kỳ kinh tế. Triển vọng trung tính.'),
('VSM_2023_parent', 'VSM', 2023, 'parent', 'Doanh nghiệp có nhiều giao dịch mua bán, cho vay với các bên liên quan thuộc cùng hệ thống Công ty mẹ (Container Việt Nam) và công ty con (Container Qui Nhơn). Các giao dịch chủ yếu là hoạt động kinh doanh thông thường, nhưng mức độ giao dịch lớn và thường xuyên, tập trung vào công ty con và công ty mẹ, đòi hỏi cần giám sát tính thị trường của các giao dịch này.', 'Nợ vay主要集中于 Công ty mẹ (Container Việt Nam) với lãi suất thả nổi theo lãi suất tiết kiệm của Vietcombank + 1%/năm. Tổng nợ vay khoảng 13.26 tỷ VND, trong đó nợ ngắn hạn 3.79 tỷ VND và nợ dài hạn 9.47 tỷ VND. Công ty có lịch trả nợ gốc định kỳ 3 tháng/lần. Áp lực trả nợ có thể tăng lên nếu lãi suất thị trường tăng hoặc dòng tiền hoạt động suy giảm.', 'Hàng tồn kho (nguyên liệu, vật liệu) trị giá 1.08 tỷ VND, không có dự phòng giảm giá và không có hàng tồn kho ứ đọng. Rủi ro tồn kho ở mức thấp.', 5, 'Công ty CP Container Miền Trung hoạt động kinh doanh dịch vụ vận tải và logistics, có kết quả kinh doanh ổn định với lợi nhuận sau thuế 11.84 tỷ VND năm 2023. Dòng tiền hoạt động kinh doanh dương mạnh (20.45 tỷ VND). Tuy nhiên, doanh nghiệp phụ thuộc lớn vào Công ty mẹ về nguồn vốn vay và có nhiều giao dịch với các bên liên quan trong hệ thống. Cơ cấu tài sản có phần lớn là tài sản cố định và khoản phải thu, cần theo dõi khả năng thu hồi các khoản phải thu lớn. Điểm rủi ro quản trị ở mức trung bình do sự phức tạp của các giao dịch liên quan và cơ cấu sở hữu tập trung.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSM_2023_consolidated', 'VSM', 2023, 'consolidated', 'Công ty có mối quan hệ phức tạp với công ty mẹ là Công ty CP Container Việt Nam và nhiều công ty cùng hệ thống. Giao dịch đáng chú ý nhất là khoản vay 13,26 tỷ VNĐ từ công ty mẹ với lãi suất thả nổi (lãi suất tiết kiệm Vietcombank + 1%/năm, điều chỉnh 3 tháng/lần). Ngoài ra có nhiều giao dịch mua bán hàng hóa dịch vụ qua lại với các công ty cùng hệ thống (VICONSHIP, Ngôi Sao Xanh, Cảng Xanh VIP, Logistics Cảng Đà Nẵng). Các giao dịch này có tính chất nội bộ tập đoàn, tuy nhiên lãi suất vay theo cơ chế thị trường nên rủi ro chuyển giá ở mức trung bình.', 'Tổng nợ vay 13.26 tỷ VNĐ (3.79 tỷ ngắn hạn + 9.47 tỷ dài hạn), toàn bộ từ công ty mẹ. Lãi suất thả nổi tạo rủi ro biến động chi phí tài chính khi lãi suất thị trường tăng. Lịch trả nợ gốc 3 tháng/lần tạo áp lực dòng tiền thường xuyên. Chi phí lãi vay năm 2023 là 1.04 tỷ VNĐ. Tuy nhiên, nợ ngắn hạn chiếm tỷ trọng thấp (28.6% tổng nợ) và dòng tiền từ hoạt động kinh doanh đạt 27.87 tỷ VNĐ, khả năng thanh toán nợ được đảm bảo.', 'Hàng tồn kho cuối kỳ chỉ có 1.13 tỷ VNĐ nguyên liệu vật liệu, không có hàng hóa thành phẩm. Không có dự phòng giảm giá, không có hàng tồn kho ứ đọng hay kém chất lượng. Không có dự án xây dựng dở dang hay bất động sản đầu tư. Rủi ro tồn kho ở mức thấp.', 4, 'Công ty CP Container Miền Trung hoạt động trong lĩnh vực logistics/container với doanh thu 264 tỷ VNĐ (giảm 18.6% so với năm trước), biên lợi nhuận gộp 9.56%. Lợi nhuận sau thuế đạt 11.75 tỷ VNĐ (giảm 26.8%). Thanh khoản tốt với tiền và tương đương tiền 37.97 tỷ VNĐ (tăng gần gấp đôi so với đầu năm), dòng tiền hoạt động kinh doanh dương 27.87 tỷ VNĐ. Tuy nhiên, công ty phụ thuộc lớn vào vay nợ từ công ty mẹ với lãi suất biến động. Cơ cấu cổ đông tập trung (công ty mẹ nắm 59.1% vốn). Công ty có quỹ đầu tư phát triển lớn 26.46 tỷ VNĐ cho thấy tiềm lực tài chính nội bộ mạnh. Triển vọng trung hạn phụ thuộc vào khả năng phục hồi doanh thu dịch vụ logistics.'),
('VST_2018_parent', 'VST', 2018, 'parent', 'Doanh nghiệp có giao dịch với công ty con và liên kết. Công ty con (SCC) mới được đầu tư 5 tỷ VND trong năm 2018 và đang kinh doanh lỗ. Công ty liên kết (PDIMEX JSC) cũng kinh doanh lỗ, đã phải trích lập dự phòng đầu tư. Có giao dịch mua bán hàng hóa và dịch vụ giữa các bên, tuy nhiên giá trị không quá lớn. Mối quan hệ này có thể ảnh hưởng đến hiệu quả hoạt động do cả hai công ty con/đều kinh doanh không hiệu quả.', 'Áp lực nợ vay rất cao với tổng nợ vay lên đến hơn 1.376 tỷ VND, trong đó nợ ngắn hạn chiếm phần lớn (1.177 tỷ VND). Hầu hết các khoản nợ vay đã quá hạn thanh toán, Công ty bị kiện ra tòa án và tàu VTC Ocean bị ngân hàng tạm giữ. Tài sản đảm bảo chủ yếu là đội tàu (giá trị còn lại 889 tỷ VND). Công ty đang trong quá trình đàm phán tái cơ cấu nợ nhưng chưa có thỏa thuận cuối cùng, rủi ro vỡ nợ là rất lớn.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ (tổng cộng 38 tỷ VND), không có dự phòng giảm giá. Chi phí xây dựng dở dang chỉ có 625 triệu VND tại địa chỉ công ty, không đáng kể. Rủi ro tồn kho thấp do giá trị không lớn và không có hàng tồn kho ứ đọng hay kém chất lượng.', 8, 'Tình hình tài chính cực kỳ khó khăn với khoản lỗ luỹ kế lên đến 1.780 tỷ VND, vốn chủ sở hữu âm (-1.155 tỷ VND). Nợ ngắn hạn vượt xa tài sản ngắn hạn (chênh lệch 1.903 tỷ VND). Doanh thu giảm 10% so với năm trước, giá vốn cao hơn doanh thu dẫn đến lỗ gộp. Chi phí lãi vay rất lớn (113 tỷ VND/năm). Công ty đang hoạt động dựa trên giả định liên tục nhờ cam kết hỗ trợ từ cổ đông lớn là Tổng Công ty Hàng hải Việt Nam (48,99% vốn). Tuy nhiên, triển vọng phụ thuộc hoàn toàn vào việc tái cơ cấu nợ thành công và cải thiện kết quả kinh doanh từ hoạt động vận tải biển đang gặp khó khăn do thị trường.'),
('VSM_2022_consolidated', 'VSM', 2022, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, đặc biệt là công ty mẹ Công ty CP Container Việt Nam, bao gồm vay nợ và mua bán hàng hóa. Lãi suất vay dựa trên lãi suất ngân hàng cộng biên độ, có vẻ thị trường. Tuy nhiên, sự phụ thuộc vào công ty mẹ có thể gây rủi ro nếu công ty mẹ gặp khó khăn.', 'Nợ vay tăng mạnh từ 4,3 tỷ VND năm trước lên 18,1 tỷ VND năm 2022, chủ yếu từ công ty mẹ. Áp lực trả nợ cao nhưng dòng tiền từ hoạt động kinh doanh vẫn dương. Tài sản thế chấp không rõ ràng, nhưng nợ được hỗ trợ bởi công ty mẹ.', 'Hàng tồn kho thấp và không có dự phòng giảm giá, rủi ro tồn kho thấp.', 4, 'Công ty có doanh thu tăng trưởng mạnh, lợi nhuận ổn định, nhưng nợ vay tăng cao từ công ty mẹ. Dòng tiền hoạt động kinh doanh đủ để trang trải chi phí, nhưng cần theo dõi rủi ro từ các giao dịch liên quan và nợ vay dài hạn.'),
('VSM_2021_parent', 'VSM', 2021, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt với công ty mẹ (Công ty CP Container Việt Nam) và công ty con (Công ty CP Container Quy Nhơn). Các giao dịch bao gồm cho vay, mua bán hàng hóa dịch vụ với giá trị lớn. Khoản vay từ công ty mẹ có lãi suất thả nổi dựa trên lãi suất tiết kiệm cộng biên 0,5%/năm, không có tài sản thế chấp. Giao dịch với công ty con cũng có lãi suất thỏa thuận. Mức độ tập trung giao dịch bên liên quan cao, đòi hỏi sự minh bạch và giám sát chặt chẽ.', 'Nợ vay chủ yếu từ công ty mẹ với tổng số dư 4,3 tỷ VNĐ, giảm so với năm trước. Lãi suất thả nổi, điều chỉnh 3 tháng/lần, tạo rủi ro biến động lãi suất. Thời hạn nợ dài (60 tháng), lịch trả nợ gốc định kỳ 3 tháng, áp lực trả nợ ngắn hạn không lớn do dòng tiền hoạt động kinh doanh dương. Không có tài sản thế chấp rõ ràng.', 'Hàng tồn kho thấp (1,5 tỷ VNĐ), chủ yếu là nguyên vật liệu và hàng hóa, không có dự phòng giảm giá. Hàng tồn kho ứ đọng, mất phẩm chất không có. Có tài sản dở dang mua sắm tài sản cố định (xe nâng) với giá trị 727 triệu VNĐ, đang trong quá trình đầu tư, rủi ro thấp.', 5, 'Công ty kinh doanh có lãi, lợi nhuận sau thuế tăng 11% so với năm trước. Biên lợi nhuận gộp khoảng 9,2%. Dòng tiền từ hoạt động kinh doanh dương và mạnh. Nợ vay giảm, cơ cấu nợ chủ yếu dài hạn từ công ty mẹ. Tuy nhiên, công ty phụ thuộc lớn vào giao dịch với bên liên quan, đặc biệt là công ty mẹ và công ty con. Quản trị công ty ở mức trung bình, cần theo dõi các giao dịch liên quan để đảm bảo tính công bằng và minh bạch.'),
('VSM_2021_consolidated', 'VSM', 2021, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là vay nợ và mua bán hàng hóa/dịch vụ với công ty mẹ và các công ty cùng công ty mẹ. Điều này cho thấy sự phụ thuộc đáng kể, tuy nhiên không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay chủ yếu từ công ty mẹ với lãi suất liên kết đến lãi suất tiết kiệm, áp lực nợ không cao, công ty có khả năng thanh toán từ dòng tiền kinh doanh và không có tài sản thế chấp nổi bật.', 'Hàng tồn kho ở mức thấp và chủ yếu là nguyên vật liệu và hàng hóa, không có dự phòng giảm giá, rủi ro tồn kho thấp. Dự án xây dựng dở dang là mua sắm tài sản cố định, không có dấu hiệu ứ đọng.', 5, 'Doanh nghiệp tăng trưởng lợi nhuận mạnh nhờ mở rộng dịch vụ vận tải và đại lý container. Tình hình tài chính ổn định, nợ vay được kiểm soát, dòng tiền kinh doanh dương. Tuy nhiên, sự phụ thuộc vào công ty mẹ trong giao dịch và tài trợ là điểm cần lưu ý. Triển vọng đầu tư tích cực trong trung hạn.'),
('VSM_2019_consolidated', 'VSM', 2019, 'consolidated', 'Công ty có nhiều giao dịch mua bán, vay nợ với các bên liên quan (đặc biệt công ty mẹ và các công ty cùng mẹ). Các khoản vay từ công ty mẹ có lãi suất ưu đãi (lãi suất tiết kiệm + 0.5%), tuy nhiên tập trung giao dịch lớn với bên liên quan có thể tạo rủi ro về tính độc lập và minh bạch trong giá chuyển nhượng.', 'Tổng nợ vay tăng mạnh từ 5.9 tỷ lên 14.7 tỷ VNĐ, chủ yếu là vay dài hạn từ công ty mẹ. Công ty có lịch trả nợ gốc và lãi rõ ràng với ân hạn 3 tháng, lãi suất thấp. Tuy nhiên, tỷ lệ nợ vay tăng nhanh có thể ảnh hưởng đến đòn bẩy tài chính và áp lực trả nợ trong tương lai.', 'Hàng tồn kho giảm từ 1.5 tỷ xuống 1.2 tỷ VNĐ, chủ yếu là nguyên vật liệu và hàng hóa thông thường, không có hàng tồn kho dở dang hay dự án xây dựng lớn. Rủi ro tồn kho thấp.', 4, 'Công ty có kết quả kinh doanh tăng trưởng tốt (LNST tăng 15%), chủ yếu nhờ lợi nhuận thanh lý tài sản. Tuy nhiên, công ty phụ thuộc lớn vào công ty mẹ về nguồn vốn vay và giao dịch kinh doanh. Nợ vay tăng mạnh nhưng được kiểm soát với lãi suất ưu đãi. Hàng tồn kho ở mức an toàn. Cần theo dõi các giao dịch với bên liên quan và cơ cấu nợ.'),
('VSM_2020_parent', 'VSM', 2020, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty mẹ và công ty con, nhưng không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay chủ yếu từ công ty mẹ với lãi suất thị trường, áp lực nợ ở mức trung bình và có thể kiểm soát được, không có tài sản thế chấp rõ ràng.', 'Hàng tồn kho bao gồm nguyên vật liệu và hàng hoá, không có dự phòng giảm giá, rủi ro thấp.', 4, 'Doanh thu và lợi nhuận tăng trưởng, tài chính ổn định nhưng cần theo dõi giao dịch bên liên quan và quản lý nợ vay. Triển vọng đầu tư trung bình.'),
('VSM_2020_consolidated', 'VSM', 2020, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là với công ty mẹ (Công ty CP Container Việt Nam) và các công ty cùng công ty mẹ, bao gồm cho vay, mua bán hàng hóa/dịch vụ. Các giao dịch này có vẻ bình thường trong hoạt động kinh doanh, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, sự tập trung vào công ty mẹ có thể tạo ra rủi ro phụ thuộc.', 'Nợ vay chủ yếu từ công ty mẹ với lãi suất dựa trên lãi suất tiết kiệm cộng 0.5%/năm, mức lãi suất hợp lý. Áp lực nợ không cao do lợi nhuận tăng trưởng tốt và dòng tiền kinh doanh dương. Tuy nhiên, nợ ngắn hạn có đáo hạn trong năm, cần theo dõi khả năng thanh toán.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và hàng hóa, không có dự phòng giảm giá và không có hàng tồn kho ứ đọng. Rủi ro tồn kho thấp.', 3, 'Công ty có tình hình tài chính ổn định với doanh thu và lợi nhuận tăng trưởng, biên lợi nhuận gộp khoảng 10%. Dòng tiền kinh doanh dương mạnh, hỗ trợ thanh toán nợ. Nợ vay tập trung ở công ty mẹ với lãi suất hợp lý. Hàng tồn kho quản lý tốt. Tuy nhiên, công ty phụ thuộc vào công ty mẹ trong một số giao dịch. Điểm rủi ro quản trị thấp, triển vọng đầu tư tích cực.'),
('VSH_2025_consolidated', 'VSH', 2025, 'consolidated', 'Công ty có giao dịch thương mại lớn với các công ty trong cùng tập đoàn (Công ty Mua bán điện - EVN) và các cổ đông lớn (REE, Tổng Công ty Phát điện 3). Các giao dịch này được thực hiện theo điều kiện thị trường và tập trung vào hoạt động kinh doanh chính (bán điện). Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường với các bên liên quan.', 'Nợ vay ngân hàng tập trung vào dài hạn với lãi suất thị trường (6,6%-7,2%/năm). Các khoản vay lớn được thế chấp bằng tài sản cố định hình thành từ dự án thủy điện (Thượng Kon Tum, Sông Hinh). Dòng tiền hoạt động kinh doanh mạnh (trên 1.400 tỷ đồng năm 2025) giúp Công ty có khả năng thanh toán nợ tốt. Tuy nhiên, Công ty có khoản vay từ Quỹ Phát triển Bắc Âu (NDF) không lãi suất nhưng có phí dịch vụ.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư, phụ tùng thay thế (102 tỷ đồng). Giá trị tồn kho giảm nhẹ so với năm trước và không có hàng tồn kho dở dang lớn. Dự phòng giảm giá hàng tồn kho được trích lập. Rủi ro tồn kho thấp.', 3, 'Công ty thủy điện có kết quả kinh doanh tăng trưởng mạnh năm 2025 với lợi nhuận sau thuế tăng 92,4% (862,6 tỷ đồng). Biên lợi nhuận gộp đạt 53,3% cho thấy hiệu quả hoạt động cao. Dòng tiền từ hoạt động kinh doanh rất mạnh (1.442 tỷ đồng) nhưng bị giảm do dòng tiền đầu tư và tài chính âm (trả nợ gốc và chia cổ tức lớn). Công ty có tài sản cố định lớn (giá trị còn lại 6.886 tỷ đồng) và đang triển khai dự án Thượng Kon Tum. Quản trị công ty minh bạch với các giao dịch bên liên quan được kiểm soát. Triển vọng tích cực nhờ vị thế trong ngành thủy điện và kế hoạch mua cổ phần GE Tây Nguyên.'),
('VSM_2019_parent', 'VSM', 2019, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt với công ty mẹ Công ty CP Container Việt Nam, bao gồm mua bán hàng hóa, dịch vụ và vay vốn. Các giao dịch này có thể ảnh hưởng đến tính độc lập của công ty.', 'Nợ vay tăng đáng kể, chủ yếu từ vay dài hạn với công ty mẹ. Lãi suất biến động theo thị trường, tạo áp lực trả nợ. Tuy nhiên, công ty không có tài sản thế chấp rõ ràng.', 'Hàng tồn kho ở mức thấp, không có dự phòng giảm giá, cho thấy rủi ro tồn kho thấp.', 6, 'Tài chính công ty tăng trưởng doanh thu và lợi nhuận, nhưng phụ thuộc lớn vào công ty mẹ về vốn và giao dịch. Nợ vay tăng, cần theo dõi khả năng thanh toán.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSH_2025_parent', 'VSH', 2025, 'parent', 'Công ty có mối quan hệ tập đoàn phức tạp với Công ty Cổ phần Cơ Điện Lạnh (công ty mẹ cao nhất), Công ty TNHH Năng lượng R.E.E (công ty mẹ), và Tổng Công ty Phát Điện 3 – CTCP (cổ đông lớn). Giao dịch trọng yếu là bán điện cho Công ty Mua bán điện thuộc Tập đoàn Điện lực Việt Nam (cùng tập đoàn với cổ đông lớn). Các giao dịch này dường như được thực hiện trên cơ sở thương mại bình thường, nhưng mức độ phụ thuộc vào các bên liên quan là rất cao, đặc biệt là doanh thu bán điện. Không có giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch giá lớn với bên liên quan được ghi nhận.', 'Công ty có tổng nợ vay lớn (khoảng 2.705 tỷ VNĐ cuối năm 2025), chủ yếu là nợ dài hạn để tài trợ Dự án Thủy điện Thượng Kon Tum. Các khoản vay có lãi suất từ 6,6% đến 7,2%/năm và được đảm bảo bằng toàn bộ tài sản hình thành từ dự án, quyền sử dụng đất và một phần tài sản cố định tại Nhà máy Thủy điện Sông Hinh. Áp lực trả nợ gốc là đáng kể (đã trả 650 tỷ trong năm), nhưng dòng tiền hoạt động kinh doanh mạnh mẽ (trên 1.441 tỷ) và giá trị tài sản thế chấp lớn làm giảm rủi ro thanh toán. Một khoản vay nhỏ hơn từ Quỹ phát triển Bắc Âu không lãi suất.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư, phụ tùng thay thế cho hoạt động sản xuất điện, với giá trị thuần khoảng 102 tỷ VNĐ. Đây là loại tồn kho ít rủi ro về ứ đọng hay giảm giá mạnh so với hàng hóa thương mại. Chi phí xây dựng cơ bản dở dang còn lại rất nhỏ (4,6 tỷ), cho thấy các dự án xây dựng đã cơ bản hoàn thành và chuyển giao vào tài sản cố định.', 6, 'Công ty Cổ phần Thủy điện Vĩnh Sơn - Sông Hinh có tình hình tài chính lành mạnh với biên lợi nhuận gộp cao (khoảng 53%), dòng tiền kinh doanh dồi dào và lợi nhuận tăng trưởng mạnh. Tuy nhiên, doanh nghiệp chịu rủi ro tập trung cao vào một khách hàng lớn (thuộc tập đoàn liên quan) và có cơ cấu vốn vay lớn để tài trợ dự án. Việc trả nợ vay và duy trì dòng tiền là trọng tâm. Công ty có các giao dịch liên quan lớn với các công ty trong tập đoàn nhưng tuân theo giá thị trường. Triển vọng tích cực nhờ nhu cầu điện ổn định và ưu đãi thuế cho dự án mới, nhưng cần theo dõi áp lực lãi suất và tỷ giá.'),
('VSH_2024_consolidated', 'VSH', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là bán điện cho Công ty Mua bán điện thuộc Tập đoàn Điện lực Việt Nam theo giá thị trường, chia cổ tức cho các cổ đông lớn và vay vốn từ công ty mẹ cao nhất. Không có giao dịch bất thường hay cho vay không lãi suất với bên liên quan.', 'Nợ vay ngân hàng ở mức cao (3.352 tỷ VND) với lãi suất từ 6.6% đến 8.5%/năm, tài sản đảm bảo là toàn bộ tài sản hình thành từ Dự án Thủy điện Thượng Kon Tum và một phần tài sản tại Nhà máy Thủy điện Sông Hinh. Dòng tiền từ hoạt động kinh doanh mạnh (1.576 tỷ VND) có thể đáp ứng các nghĩa vụ trả nợ.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư, phụ tùng thay thế với dự phòng giảm giá không đáng kể (518 triệu VND). Dự án xây dựng dở dang giảm do quyết toán, không có dấu hiệu ứ đọng.', 3, 'Công ty thủy điện có lợi nhuận giảm 55% so với năm trước do sản lượng điện thấp, nhưng vẫn duy trì biên lợi nhuận gộp cao (47.85%). Nợ vay giảm, dòng tiền hoạt động kinh doanh mạnh, triển vọng ổn định.'),
('VSH_2023_consolidated', 'VSH', 2023, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là bán điện cho Công ty Mua bán điện - Tập đoàn Điện lực Việt Nam và chi trả cổ tức cho cổ đông lớn, không có dấu hiệu bất thường. Tuy nhiên, doanh thu bán điện phụ thuộc lớn vào bên liên quan này, tạo rủi ro tập trung khách hàng.', 'Công ty có nợ vay dài hạn lớn với lãi suất cao (8%-12%/năm) và thế chấp toàn bộ tài sản tại Nhà máy Thủy điện Thượng Kon Tum, gây áp lực tài chính và rủi ro lãi suất biến động.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư, phụ tùng thay thế, giá trị ổn định và không có dự phòng giảm giá. Dự án Thủy điện Thương Kon Tum đang trong quá trình quyết toán, không có dấu hiệu ứ đọng lớn.', 4, 'Công ty có biên lợi nhuận gộp cao (~60.6%) nhờ hoạt động thủy điện, nhưng lợi nhuận giảm so với năm trước do doanh thu bán điện giảm. Nợ vay lớn và chi phí lãi vay cao là thách thức. Tình hình tài chính ổn định với dòng tiền kinh doanh dương, nhưng cần theo dõi rủi ro liên quan đến bên liên quan và nợ.'),
('VSH_2024_parent', 'VSH', 2024, 'parent', 'Công ty có giao dịch lớn với bên liên quan, đặc biệt là doanh thu bán điện cho Công ty Mua bán điện thuộc EVN (chiếm gần 100% doanh thu), tạo ra sự phụ thuộc cao. Các giao dịch vay mượn với công ty mẹ REE có thể được ưu đãi, nhưng không có dấu hiệu bất thường rõ ràng về giá hay điều kiện.', 'Nợ vay dài hạn lớn (hơn 3.350 tỷ VND), chủ yếu để đầu tư dự án thủy điện Thượng Kon Tum. Áp lực trả nợ cao, nhưng dòng tiền kinh doanh mạnh, lãi suất dao động từ 6.6% đến 8.5%/năm. Tài sản thế chấp bao gồm quyền sử dụng đất và cổ phiếu, giảm rủi ro vỡ nợ.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư thay thế, rủi ro thấp. Dự án xây dựng dở dang Thượng Kon Tum đang trong giai đoạn quyết toán, có thể có chậm trễ nhưng không đáng kể.', 4, 'Công ty có tình hình tài chính ổn định, dòng tiền kinh doanh tích cực, nhưng lợi nhuận giảm so với năm trước do sản lượng điện thấp. Nợ vay được kiểm soát, quản trị minh bạch với cơ cấu cổ đông rõ ràng. Triển vọng trung hạn phụ thuộc vào hiệu suất sản xuất điện và tiến độ dự án.'),
('VSH_2022_consolidated', 'VSH', 2022, 'consolidated', 'Các giao dịch bên liên quan chủ yếu là bán điện cho Công ty Mua bán điện thuộc Tập đoàn Điện lực Việt Nam (cổ đông lớn), chia cổ tức cho công ty mẹ và cổ đông lớn, lãi vay và trái phiếu cho công ty mẹ cao nhất và công ty con của cổ đông lớn. Giao dịch được thực hiện theo thỏa thuận hợp đồng, không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay tổng cộng hơn 4.000 tỷ VND, chủ yếu là vay dài hạn từ các ngân hàng thương mại và phát hành trái phiếu. Tài sản đảm bảo bao gồm toàn bộ nhà máy thủy điện và tiền gửi ngân hàng. Áp lực nợ vay cao nhưng được hỗ trợ bởi doanh thu bán điện ổn định và dòng tiền kinh doanh mạnh. Lãi suất vay dao động từ 9,9% đến 12,05%/năm, có khoản vay ngoại tệ với lãi suất LIBOR+.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư, phụ tùng thay thế với giá trị giảm nhẹ so với năm trước, rủi ro thấp. Dự án xây dựng dở dang (Thủy điện Thượng Kon Tum) đang trong quá trình quyết toán, đã giảm đáng kể. Dự án Vĩnh Sơn 2 và 3 đã được đánh giá không tạo lợi ích kinh tế và kết chuyển, thể hiện sự thận trọng trong quản lý tài sản.', 4, 'Công ty có sức khỏe tài chính tốt với lợi nhuận sau thuế tăng mạnh nhờ doanh thu bán điện tăng cao. Nợ vay lớn nhưng được kiểm soát bởi dòng tiền kinh doanh dồi dào và tài sản đảm bảo là các nhà máy thủy điện. Quản trị rủi ro ở mức trung bình, các giao dịch bên liên quan minh bạch. Triển vọng đầu tư tích cực trong dài hạn khi các dự án điện đi vào vận hành ổn định.'),
('VSH_2023_parent', 'VSH', 2023, 'parent', 'Giao dịch với bên liên quan chủ yếu là bán điện và chia cổ tức, không có giao dịch bất thường rõ ràng.', 'Công ty có nợ vay lớn với lãi suất cao, tài sản thế chấp đầy đủ, áp lực trả nợ trung bình.', 'Hàng tồn kho chủ yếu là vật tư thay thế, rủi ro thấp. Dự án xây dựng dở dang có thể bị chậm tiến độ.', 5, 'Công ty là nhà sản xuất điện thủy điện, doanh thu ổn định nhưng giảm, gánh nặng nợ cao, tài sản thế chấp đảm bảo. Sức khỏe tài chính trung bình.'),
('VSH_2022_parent', 'VSH', 2022, 'parent', 'Doanh thu bán điện 100% đến từ Công ty Mua bán điện - Tập đoàn Điện lực Việt Nam (bên liên quan qua cổ đông lớn). Công ty phát hành trái phiếu trị giá 219 tỷ VND cho Công ty mẹ cao nhất (Công ty Cổ phần Cơ Điện Lạnh) và Công ty con của cổ đông lớn (Công ty Cổ phần Nhiệt điện Bà Rịa). Các giao dịch này có tính tập trung cao, phụ thuộc lớn vào một nhóm liên quan.', 'Tổng nợ vay khoảng 4.050 tỷ VND, trong đó nợ dài hạn chiếm phần lớn (~3.915 tỷ). Các khoản vay ngân hàng đầu tư xây dựng Dự án Thủy điện Thượng Kon Tum với lãi suất cao 9.9%-12.05%/năm. Chi phí lãi vay năm 2022 là 408 tỷ VND. Tài sản thế chấp chủ yếu là các nhà máy thủy điện. Nợ ngắn hạn đáo hạn trong năm tới ~135 tỷ VND, cần lưu ý khả năng trả nợ.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư, phụ tùng thay thế (~100 tỷ VND), mức ổn định. Dự án Thủy điện Vĩnh Sơn 2 và 3 đã bị đánh giá không tạo ra lợi ích kinh tế và đã trích lập dự phòng toàn bộ 99.5 tỷ VND. Dự án Thủy điện Thượng Kon Tum vẫn đang trong quá trình quyết toán với giá trị dở dang 47.6 tỷ VND.', 6, 'Công ty Cổ phần Thủy điện Vĩnh Sơn - Sông Hinh có kết quả kinh doanh ấn tượng năm 2022 với doanh thu thuần 3.085 tỷ VND (tăng 91% so với năm trước), lợi nhuận sau thuế 1.264 tỷ VND (tăng 227%), và biên lợi nhuận gộp đạt 65.5%. Điểm mạnh là dòng tiền hoạt động kinh doanh mạnh (1.507 tỷ VND), trả được nợ gốc vay 1.051 tỷ VND và chia cổ tức 236 tỷ VND. Tuy nhiên, Công ty phụ thuộc 100% vào EVN trong tiêu thụ điện, có nợ vay lớn với lãi suất cao, và đã phải xử lý dự án Vĩnh Sơn 2&3 không khả thi. Điểm rủi ro quản trị ở mức trung bình do giao dịch liên quan lớn nhưng tuân thủ hợp đồng rõ ràng.'),
('VSH_2021_consolidated', 'VSH', 2021, 'consolidated', 'Giao dịch với các bên liên quan bao gồm bán điện cho Công ty Mua bán điện thuộc EVN, vay và lãi vay từ công ty mẹ và công ty liên kết. Các giao dịch này dường như được thực hiện trên cơ sở thỏa thuận, nhưng cần giám sát tính công bằng.', 'Công ty có nợ vay lớn, chủ yếu để tài trợ dự án Thủy điện Thượng Kon Tum. Nợ được đảm bảo bằng tài sản dự án, với lãi suất cố định từ 8% đến 9%. Áp lực trả nợ cao, nhưng dòng tiền từ hoạt động kinh doanh mạnh có thể hỗ trợ.', 'Hàng tồn kho chủ yếu là thiết bị, vật tư thay thế với giá trị ổn định. Các dự án xây dựng dở dang đã được chuyển giao và đưa vào hoạt động, nên rủi ro thấp.', 3, 'Công ty có sức khỏe tài chính tốt với lợi nhuận tăng trưởng mạnh trong năm 2021 nhờ Nhà máy Thủy điện Thượng Kon Tum đi vào hoạt động. Tuy nhiên, nợ vay cao là rủi ro. Triển vọng đầu tư tích cực với hoạt động sản xuất điện ổn định.'),
('VSH_2021_parent', 'VSH', 2021, 'parent', 'Doanh nghiệp có giao dịch lớn với các bên liên quan. Doanh thu bán điện chủ yếu từ Công ty Mua bán điện - EVN (cổ đông lớn gián tiếp) đạt 1.611 tỷ VND, chiếm 100% doanh thu thuần. Công ty vay 33 tỷ VND ngắn hạn từ công ty mẹ cao nhất (Cơ Điện Lạnh) và phát hành 652 tỷ VND trái phiếu cho các công ty trong tập đoàn (Cơ Điện Lạnh 460 tỷ, Nhiệt điện Bà Rịa 192 tỷ). Các giao dịch này tuân theo điều khoản hợp đồng nhưng tạo sự phụ thuộc lớn vào tập đoàn mẹ về mặt doanh thu và nguồn vốn. Rủi ro trung bình do cấu trúc tập đoàn rõ ràng.', 'Tổng nợ phải trả 6.007 tỷ VND, chiếm 60% tổng tài sản (10.028 tỷ VND). Nợ vay tổng cộng 5.069 tỷ VND (ngắn hạn 142 tỷ, dài hạn 4.927 tỷ). Phần lớn nợ dài hạn là vay ngân hàng và trái phiếu để tài trợ Dự án Thủy điện Thượng Kon Tum. Lãi suất vay từ 8-8,9%/năm, riêng vay ngoại tệ LIBOR+2,97%. Chi phí lãi vay năm 2021 là 323 tỷ VND (năm trước chỉ 1,2 tỷ). Tài sản thế chấp lớn bao gồm toàn bộ 3 nhà máy thủy điện. Dù dự án Thượng Kon Tum đã vận hành thương mại và bắt đầu tạo doanh thu, áp lực trả nợ vẫn đáng kể với dòng tiền 754 tỷ từ hoạt động kinh doanh.', 'Hàng tồn kho 101,9 tỷ VND chủ yếu là thiết bị, vật tư, phụ tùng thay thế dài hạn (giá trị tăng từ 44 tỷ lên 102 tỷ do tích lũy). Dự án Vĩnh Sơn 2&3 trị giá 98,3 tỷ VND vẫn đang trong giai đoạn triển khai và chưa có tiến độ cụ thể về thời gian hoàn thành. Dự án Thượng Kon Tum còn 74,1 tỷ VND đang quyết toán, trong khi đã chuyển 9.105 tỷ sang TSCĐ - cho thấy dự án về cơ bản đã hoàn thành. Rủi ro tồn kho thấp do chủ yếu là vật tư dự phòng cho vận hành nhà máy.', 5, 'Công ty Cổ phần Thủy điện Vĩnh Sơn - Sông Hinh (VSH) là doanh nghiệp thủy điện có quy mô lớn với 3 nhà máy hoạt động (tổng công suất 356MW). Năm 2021 đánh dấu bước ngoặt khi Dự án Thượng Kon Tum (220MW) hoàn thành và đi vào vận hành thương mại, giúp doanh thu tăng gấp 4,7 lần lên 1.611 tỷ VND, lợi nhuận sau thuế đạt 387 tỷ VND. Tuy nhiên, công ty đang chịu áp lực nợ vay lớn (5.069 tỷ VND) với chi phí lãi vay 323 tỷ VND, tài sản thế chấp toàn bộ 3 nhà máy. Giao dịch với bên liên quan đáng kể (100% doanh thu từ EVN, vay mượn từ tập đoàn mẹ). Công ty đang có tranh chấp pháp lý với nhà thầu Trung Quốc liên quan dự án Thượng Kon Tum nhưng đánh giá rủi ro thấp. Triển vọng tích cực khi nhà máy Thượng Kon Tum vận hành ổn định sẽ tạo dòng tiền mạnh để trả nợ.'),
('VSH_2020_parent', 'VSH', 2020, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, đặc biệt là vay nợ lớn từ Công ty Cổ phần Cơ Điện Lạnh (công ty mẹ của cổ đông lớn) với lãi suất thị trường (9-10%/năm). Doanh thu bán điện tập trung cao vào Công ty Mua bán điện (công ty trong cùng tập đoàn). Các giao dịch được thực hiện theo giá thị trường và không có dấu hiệu bất thường rõ ràng, nhưng sự phụ thuộc lớn vào các bên liên quan trong tập đoàn đặt ra rủi ro về tính độc lập và transfer pricing.', 'Tổng nợ vay rất lớn (hơn 5.767 tỷ VND), trong đó nợ dài hạn chiếm phần lớn. Công ty phải thế chấp hầu hết tài sản chính (nhà máy, quyền sử dụng đất dự án) để đảm bảo cho các khoản vay. Áp lực trả nợ gốc và lãi là đáng kể, đặc biệt khi dòng tiền hoạt động kinh doanh có thể bị ảnh hưởng bởi hoạt động của dự án thủy điện. Tuy nhiên, các khoản vay có kỳ hạn dài và được cam kết hỗ trợ từ cổ đông lớn.', 'Hàng tồn kho chủ yếu là vật liệu xây dựng cơ bản cho Dự án Thủy điện Thượng Kon Tum. Rủi ro tồn kho thấp vì đây là vật liệu chuyên dụng cho dự án cụ thể và dự án đang trong giai đoạn hoàn thành. Dự án xây dựng dở dang có giá trị rất lớn và đang được triển khai, rủi ro ứ đọng thấp nếu dự án đi vào vận hành đúng tiến độ.', 5, 'Công ty có nền tảng tài sản cố định lớn và dòng tiền ổn định từ hoạt động sản xuất điện. Tuy nhiên, doanh nghiệp đang trong giai đoạn đầu tư mạnh vào Dự án Thủy điện Thượng Kon Tum, dẫn đến nợ vay cao và tài sản bị thế chấp. Lợi nhuận gộp tốt nhưng bị chi phối bởi giao dịch với bên liên quan trong tập đoàn. Rủi ro chính là khả năng hoàn thành và vận hành hiệu quả dự án mới, cũng như áp lực trả nợ. Điểm mạnh là sự hỗ trợ từ các cổ đông lớn và dòng tiền từ hoạt động kinh doanh hiện tại.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSH_2020_consolidated', 'VSH', 2020, 'consolidated', 'Công ty có quan hệ giao dịch mật thiết với các công ty trong Tập đoàn Điện lực Việt Nam (EVN) và cổ đông lớn Công ty Cổ phần Cơ Điện Lạnh. Doanh thu bán điện gần như hoàn toàn phụ thuộc vào Công ty Mua bán điện thuộc EVN. Các khoản vay từ bên liên quan có lãi suất thị trường (9-10%/năm). Tổng thể, rủi ro giao dịch bên liên quan ở mức trung bình do tính chất ngành và mối quan hệ sở hữu phức tạp.', 'Tổng nợ vay phải trả rất lớn (gần 5.768 tỷ VND), chiếm tỷ trọng cao trong cơ cấu tài sản. Phần lớn nợ dài hạn được thế chấp bằng tài sản hình thành từ Dự án Thủy điện Thượng Kon Tum, tạo áp lực trả nợ lớn khi dự án vận hành. Dòng tiền từ hoạt động kinh doanh dương nhưng không đủ bù đắp dòng tiền đầu tư âm mạnh, dẫn đến phải vay nợ mới liên tục. Công ty có rủi ro về thanh khoản nếu dự án chậm tiến độ.', 'Hàng tồn kho chủ yếu là vật liệu xây dựng cơ bản cho Dự án Thủy điện Thượng Kon Tum, không có hàng thành phẩm tồn kho. Dự án xây dựng dở dang lớn (gần 8.800 tỷ VND), chiếm tỷ trọng lớn trong tổng tài sản. Rủi ro chính là tiến độ dự án bị chậm trễ hoặc chi phí phát sinh vượt dự toán.', 5, 'Công ty có nền tảng kinh doanh ổn định với hoạt động sản xuất điện năng và lợi nhuận tăng trưởng. Tuy nhiên, áp lực nợ vay rất lớn do đầu tư mạnh vào Dự án Thủy điện Thượng Kon Tum. Dự án này là yếu tố then chốt cho tăng trưởng tương lai nhưng cũng tạo ra rủi ro tài chính đáng kể. Triển vọng phụ thuộc vào tiến độ hoàn thành và vận hành hiệu quả của dự án.'),
('VSH_2019_parent', 'VSH', 2019, 'parent', 'Công ty có giao dịch bán điện với Công ty Mua bán điện – Tập đoàn Điện lực Việt Nam (bên liên quan) với giá trị lớn, đây là hoạt động kinh doanh chính. Tuy nhiên, công ty vay từ các bên liên quan với lãi suất cao (10-11,5%) có thể gây áp lực tài chính. Giao dịch với công ty con (mua dịch vụ) và công ty liên kết (cổ tức) ở mức hợp lý.', 'Công ty có nợ vay lớn, chủ yếu là nợ dài hạn để tài trợ Dự án Thủy điện Thượng Kon Tum, với lãi suất cao (9,8-10,5%). Nợ được đảm bảo bằng tài sản dự án, tạo rủi ro nếu dự án gặp vấn đề. Áp lực trả nợ gốc và lãi đáng kể, đặc biệt khi dự án còn trong giai đoạn xây dựng.', 'Hàng tồn kho chủ yếu là vật liệu xây dựng cho dự án, giảm mạnh so với năm trước. Dự án xây dựng dở dang lớn, nếu tiến độ chậm trễ hoặc chi phí tăng, có thể gây rủi ro suy giảm giá trị.', 6, 'Công ty là nhà sản xuất điện thủy điện, đang đầu tư mạnh vào Dự án Thủy điện Thượng Kon Tum bằng nợ vay. Lợi nhuận giảm doanh thu bán điện giảm và chi phí tài chính tăng. Dòng tiền từ hoạt động kinh doanh dương nhưng không đủ bù đắp đầu tư. Triển vọng phụ thuộc vào tiến độ và hiệu quả của dự án mới. Rủi ro trung bình do đòn bẩy tài chính cao và phụ thuộc vào điều kiện thủy văn.'),
('VSH_2018_consolidated', 'VSH', 2018, 'consolidated', 'Giao dịch với bên liên quan tập trung chủ yếu vào bán điện cho Công ty Mua bán Điện thuộc Tập đoàn Điện lực Việt Nam (EVN) - đây là khách hàng truyền thống và là đối tác kinh doanh chính của doanh nghiệp. Các giao dịch còn lại là trả cổ tức cho cổ đông lớn (Tổng Công ty Phát điện 3, Công ty Cổ phần Cơ điện lạnh) và nhận cổ tức từ công ty liên kết (Du lịch Bình Định). Các giao dịch này được thực hiện theo hợp đồng và điều khoản thương mại, không có dấu hiệu giao dịch bất thường hay chuyển giá. Doanh nghiệp không có giao dịch cho vay, mua bán tài sản bất thường với bên liên quan.', 'Tổng nợ vay đạt 4.653.603.119.658 VND, trong đó nợ dài hạn chiếm phần lớn (4.529.108.403.846 VND) để tài trợ Dự án Thủy điện Thương Kon Tum. Lãi suất vay dao động 9,4%-10,4%/năm (VND) và LIBOR+2,97% (USD). Chi phí lãi vay thực tế ghi nhận trong năm chỉ 1.385.065.857 VND do phần lớn lãi vay được vốn hóa vào giá trị dự án (402.992.309.842 VND). Tuy nhiên, áp lực nợ rất lớn khi dự án chưa hoàn thành và chưa tạo ra dòng tiền; nợ nước ngoài 24.670.369 USD tiềm ẩn rủi ro tỷ giá. Tài sản đảm bảo chủ yếu là quyền sử dụng đất và tài sản hình thành trong tương lai của dự án.', 'Hàng tồn kho 240.244.250.270 VND chủ yếu là vật liệu xây dựng phục vụ Dự án Thủy điện Thương Kon Tum (169.490.972.887 VND). Chi phí xây dựng cơ bản dở dang rất lớn (6.476.204.585.014 VND) với phần phát sinh bổ sung 155.292.619.174 VND chưa được phê duyệt phụ lục hợp đồng, có thể thay đổi khi ký kết chính thức. Rủi ro tồn kho ở mức trung bình do vật liệu tập trung vào dự án cụ thể, nếu dự án bị trì hoãn hoặc phát sinh thêm chi phí sẽ ảnh hưởng đến giá trị tồn kho.', 6, 'Công ty Thủy điện Vĩnh Sơn – Sông Hinh có nền tảng kinh doanh ổn định với tỷ suất lợi nhuận gộp cao (61,97%) từ hoạt động sản xuất điện. Lợi nhuận sau thuế đạt 306.207.174.880 VND, tăng 7,8% so với năm trước. Điểm mạnh là doanh thu từ bán điện cho EVN ổn định và dòng tiền từ hoạt động kinh doanh dương mạnh (420 tỷ). Tuy nhiên, áp lực tài chính lớn khi nợ vay lên tới 4.653 tỷ đồng chủ yếu đầu tư vào Dự án Thủy điện Thương Kon Tum (220MW) - dự án có quy mô lớn, thời gian thi công dài và đã phát sinh chi phí bổ sung chưa được phê duyệt. Vụ kiện với Tổ hợp nhà thầu Huadong – CR18G là rủi ro pháp lý cần theo dõi. Dự án khi hoàn thành sẽ là động lực tăng trưởng chính nhưng tiến độ và hiệu quả đầu tư cần được giám sát chặt chẽ.'),
('VSH_2019_consolidated', 'VSH', 2019, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan: (1) Doanh thu bán điện tập trung vào Công ty Mua bán Điện – EVN (400.151 tỷ VND, chiếm ~100% doanh thu) tạo sự phụ thuộc lớn; (2) Cho vay ngắn hạn với lãi suất cao (10-11,5%/năm) cho Công ty Cổ phần Cơ Điện Lạnh và Công ty Cổ phần Dịch Vụ và Kỹ thuật Cơ Điện Lạnh tổng cộng 98,6 tỷ VND; (3) Mua trái phiếu phát hành bởi Công ty Cổ phần Cơ Điện Lạnh trị giá 494,8 tỷ VND với tài sản đảm bảo là tài sản của Nhà máy Thủy điện Vĩnh Sơn - đây là giao dịch lớn đáng lưu ý vì bên liên quan phát hành trái phiếu được đảm bảo bằng tài sản của công ty phát hành; (4) Tổng giao dịch với bên liên quan chiếm tỷ trọng lớn trong hoạt động kinh doanh và đầu tư của doanh nghiệp.', 'Tổng nợ vay lên đến 5.371 tỷ VND (tăng từ 4.654 tỷ VND đầu năm), trong đó nợ dài hạn chiếm 4.957 tỷ VND. Áp lực nợ vay rất lớn khi doanh thu thuần giảm 29% (từ 564 tỷ xuống 400 tỷ VND). Phần lớn nợ vay dài hạn ngân hàng (tổng 4.462 tỷ VND) được đảm bảo bằng tài sản Dự án Thủy điện Thượng Kon Tum vẫn đang trong giai đoạn xây dựng chưa tạo ra dòng tiền. Công ty còn phát hành trái phiếu 494,8 tỷ VND cho bên liên quan. Nợ vay ngắn hạn tăng mạnh từ 124 tỷ lên 414 tỷ VND. Tỷ lệ nợ/vốn chủ sở hữu ~1,71 cho thấy đòn bẩy tài chính cao.', 'Hàng tồn kho giảm mạnh từ 240 tỷ xuống 105 tỷ VND, chủ yếu do giảm vật liệu xây dựng cơ bản (từ 210 tỷ xuống 102 tỷ VND). Dự án Thủy điện Thượng Kon Tum có chi phí xây dựng dở dang lên đến 7.912 tỷ VND (tăng 1.436 tỷ VND trong năm) và tổng cam kết vốn 1.051 tỷ VND. Dự án này vẫn chưa hoàn thành và chưa tạo ra dòng tiền, tiềm ẩn rủi ro về tiến độ và chi phí phát sinh. Vụ kiện trọng tài với Tổ hợp nhà thầu Huadong – CR18G liên quan đến dự án này đã có phán quyết buộc Công ty bồi thường 1.974 tỷ đồng, tuy nhiên phán quyết đã bị hủy.', 7, 'Công ty Cổ phần Thủy điện Vĩnh Sơn – Sông Hinh là doanh nghiệp sản xuất điện năng có vị thế ổn định với tỷ suất lợi nhuận gộp cao (~49,3%) và lợi nhuận sau thuế 159 tỷ VND. Tuy nhiên, doanh thu giảm mạnh 29% do yếu tố thủy văn. Rủi ro chính là: (1) Đầu tư lớn vào Dự án Thủy điện Thượng Kon Tum (8.021 tỷ VND chi phí dở dang) chưa tạo ra doanh thu, gia tăng đòn bẩy tài chính; (2) Giao dịch với bên liên quan phức tạp, đặc biệt khoản mua trái phiếu 495 tỷ VND từ Công ty Cơ Điện Lạnh; (3) Nợ vay tăng mạnh, chủ yếu phục vụ đầu tư xây dựng; (4) Vụ kiện trọng tài liên quan đến dự án Thượng Kon Tum. Triển vọng phụ thuộc vào tiến độ hoàn thành Dự án Thượng Kon Tum và điều kiện thủy văn.'),
('VSH_2018_parent', 'VSH', 2018, 'parent', '关联方交易主要涉及销售电力和支付股息，交易价格基于市场条件，未见明显异常风险。', '公司长期债务较高，主要用于建设项目，利率在9.4%至10.4%之间，部分贷款有担保。债务压力存在，但项目未来可能产生现金流。', '存货主要是建设材料，用于在建水电项目，如果项目延迟，可能面临减值风险。', 5, '公司盈利稳定，毛利率较高，但依赖单一客户（电力公司），有大型在建项目导致高债务，且面临诉讼风险，整体财务健康状况中等。'),
('VSH_2017_consolidated', 'VSH', 2017, 'consolidated', 'Doanh thu bán điện phụ thuộc lớn vào Công ty Mua bán Điện thuộc Tập đoàn Điện lực Việt Nam (bên liên quan). Đây là giao dịch thương mại bình thường trong ngành điện, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch giá bất hợp lý.', 'Nợ vay dài hạn lớn (hơn 3.570 tỷ VND) chủ yếu để đầu tư dự án Thủy điện Thượng Kon Tum, được đảm bảo bằng toàn bộ tài sản hình thành từ dự án. Áp lực trả nợ sẽ tăng khi dự án đi vào hoạt động. Có rủi ro tỷ giá đối với khoản vay ngoại tệ từ Ngân hàng Raiffeisen.', 'Hàng tồn kho chủ yếu là vật liệu xây dựng cơ bản cho dự án Thủy điện Thượng Kon Tum, không có trích lập dự phòng giảm giá. Dự án xây dựng dở dang tăng mạnh, phản ánh tiến độ đầu tư tích cực vào dự án mới.', 4, 'Công ty hoạt động ổn định trong lĩnh vực sản xuất điện, lợi nhuận sau thuế tăng trưởng khoảng 10% so với năm trước. Dòng tiền hoạt động kinh doanh mạnh, đủ để trả lãi vay và tài trợ một phần đầu tư. Tuy nhiên, nợ vay dài hạn tăng mạnh để tài trợ dự án Thủy điện Thượng Kon Tum tạo áp lực tài chính đáng kể trong trung hạn. Triển vọng phụ thuộc vào tiến độ và hiệu quả vận hành của dự án mới.'),
('VSH_2016_consolidated', 'VSH', 2016, 'consolidated', 'Rủi ro liên quan đến giao dịch với các bên liên quan ở mức trung bình. Doanh thu bán điện tập trung cao vào Công ty Mua bán điện (Tập đoàn Điện lực Việt Nam) là khách hàng nhà nước. Các giao dịch nhận cổ tức từ các cổ đông lớn và công ty liên kết là hoạt động đầu tư thông thường, không có dấu hiệu bất thường rõ ràng.', 'Rủi ro nợ vay ở mức CAO. Công ty có tổng nợ vay (ngắn và dài hạn) lên đến hơn 5.000 tỷ đồng, phần lớn là nợ dài hạn với thời gian đáo hạn đến 2025-2035 để tài trợ cho Dự án Thủy điện Thượng Kon Tum có vốn đầu tư lớn. Tài sản thế chấp chủ yếu là các dự án và nhà máy đang hoạt động/khởi công. Áp lực trả nợ gốc và lãi trong dài hạn là đáng kể, phụ thuộc vào dòng tiền từ hoạt động kinh doanh điện và khả năng giải ngân, vận hành dự án mới.', 'Rủi ro hàng tồn kho ở mức TRUNG BÌNH. Hàng tồn kho chủ yếu là nguyên vật liệu cho dự án xây dựng, không có trích lập dự phòng. Giá trị tồn kho tăng nhẹ. Các dự án xây dựng dở dang có giá trị lớn nhưng là đầu tư chiến lược, chưa có dấu hiệu ứ đọng hay chậm tiến độ nghiêm trọng được nêu rõ trong báo cáo.', 4, 'Công ty có hoạt động kinh doanh cốt lõi (sản xuất điện) mang lại lợi nhuận ổn định và biên lợi nhuận gộp tốt (~62%). Tuy nhiên, rủi ro tài chính主要集中 ở lượng nợ vay rất lớn用于 đầu tư dự án mới (Thượng Kon Tum). Dòng tiền hoạt động kinh doanh mạnh nhưng不足以覆盖 toàn bộ nhu cầu đầu tư,导致 dòng tiền đầu tư và tài chính âm nặng. Sức khỏe tài chính短期 do dự án dở dang, triển vọng phụ thuộc vào tiến độ và hiệu quả của Dự án Thượng Kon Tum. Điểm rủi ro quản trị ở mức trung bình (4/10) do cơ cấu cổ đông rõ ràng và không có giao dịch bất thường đáng ngờ.'),
('VSH_2016_parent', 'VSH', 2016, 'parent', 'Doanh nghiệp có giao dịch lớn với Tập đoàn Điện lực Việt Nam (bán điện) và các công ty liên quan. Cổ tức trả cho cổ đông lớn. Không thấy giao dịch bất thường nhưng phụ thuộc vào Tập đoàn Điện lực Việt Nam.', 'Nợ vay lớn, chủ yếu là vay dài hạn để đầu tư dự án thủy điện. Tài sản thế chấp là các dự án và tài sản cố định. Áp lực trả nợ tương đối cao.', 'Hàng tồn kho không lớn, chủ yếu là nguyên vật liệu. Dự án xây dựng dở dang lớn, cần theo dõi tiến độ.', 5, 'Doanh nghiệp có tiềm năng từ các dự án thủy điện nhưng đối mặt với rủi ro nợ vay và phụ thuộc vào Tập đoàn Điện lực Việt Nam.'),
('VSH_2017_parent', 'VSH', 2017, 'parent', 'Giao dịch với các bên liên quan chủ yếu là bán điện và trả cổ tức, được thực hiện theo giá và điều khoản thị trường thông thường, không có dấu hiệu bất thường đáng kể.', 'Công ty có nợ vay lớn chủ yếu phục vụ đầu tư xây dựng dự án Thủy điện Thương Kon Tum, với thời hạn dài và lãi suất cố định. Tài sản thế chấp bao gồm quyền sử dụng đất và tài sản hình thành từ dự án, giảm rủi ro. Tuy nhiên, áp lực trả nợ có thể tăng khi dự án đi vào hoạt động.', 'Hàng tồn kho chủ yếu là vật liệu xây dựng cơ bản cho dự án Thủy điện Thương Kon Tum, và chi phí xây dựng cơ bản dở dang cho các dự án thủy điện. Các dự án đang trong giai đoạn xây dựng, có rủi ro chậm tiến độ hoặc tăng chi phí.', 5, 'Công ty là nhà sản xuất điện thủy điện với doanh thu ổn định từ hoạt động bán điện. Đang đầu tư mạnh vào dự án Thủy điện Thương Tum, làm tăng nợ vay và tài sản dở dang. Lợi nhuận tăng trưởng, nhưng dòng tiền từ hoạt động kinh doanh đủ để trang trải chi phí. Triển vọng phụ thuộc vào tiến độ và hiệu quả của dự án mới.'),
('VSH_2015_consolidated', 'VSH', 2015, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là bán điện cho Tập đoàn Điện lực Việt Nam (EVN) và trả cổ tức cho các cổ đông lớn (Tổng Công ty Phát điện 3 - thành viên của EVN, và SCIC). Mối quan hệ tập trung vào ngành điện. Không có dấu hiệu giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn, tuy nhiên sự phụ thuộc lớn vào EVN trong mảng doanh thu là một rủi ro.', 'Tỷ lệ nợ thuần/vốn chủ sở hữu tăng mạnh từ 0.06 (2014) lên 0.31 (2015), phản ánh mức vay nợ lớn để tài trợ cho Dự án Thủy điện Thượng Kon Tum. Nợ dài hạn tăng vọt, chủ yếu là các khoản vay hợp vốn từ nhiều ngân hàng với lãi suất thả nổi (cộng với 3.5% trên lãi suất tiết kiệm), tạo áp lực trả nợ và rủi ro lãi suất. Phần lớn tài sản cố định và dự án đã được thế chấp làm tài sản đảm bảo.', 'Hàng tồn kho tăng mạnh chủ yếu do vật liệu xây dựng cho Dự án Thủy điện Thượng Kon Tum. Dự án xây dựng dở dang có giá trị rất lớn (gần 2.180 tỷ VND) và là trọng tâm đầu tư. Rủi ro chính là tiến độ dự án bị chậm trễ (đã có tranh chấp với nhà thầu cũ), có thể dẫn đến tăng chi phí, ảnh hưởng đến dòng tiền và khả năng hoàn thành dự án đúng kế hoạch.', 5, 'Công ty có nền tảng kinh doanh cốt lõi (thủy điện) mang lại dòng tiền kinh doanh ổn định trong năm 2015. Tuy nhiên, trọng tâm lớn hiện nay là triển khai Dự án Thủy điện Thượng Kon Tum đòi hỏi nguồn vốn đầu tư khổng lồ, đã làm tăng đột biến nợ vay và nợ phải trả ngắn hạn. Dòng tiền từ hoạt động kinh doanh trong năm dương, nhưng dòng tiền hoạt động đầu tư âm nặng do giải ngân cho dự án. Công ty đang trong giai đoạn đầu tư mạnh, đòn bẩy tài chính tăng cao, phụ thuộc vào tiến độ giải ngân và hoàn thành dự án cũng như biến động lãi suất. Cần theo dõi sát tiến độ dự án và tranh chấp pháp lý.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSH_2015_parent', 'VSH', 2015, 'parent', 'Công ty có giao dịch mua hàng với công ty con và nhận cổ tức từ công ty liên kết. Không phát hiện giao dịch bất thường đáng kể như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Nợ vay tăng mạnh từ 395 tỷ lên 2.025 tỷ VND, chủ yếu để tài trợ Dự án Thủy điện Thượng Kon Tum. Áp lực trả nợ cao, đặc biệt nợ dài hạn đáo hạn sau 12 tháng lên đến 1.774 tỷ VND. Tài sản thế chấp bao gồm tài sản cố định của Nhà máy Thủy điện Sông Hinh và quyền sử dụng đất, tài sản hình thành trong tương lai của dự án. Công ty có dòng tiền hoạt động kinh doanh dương nhưng không đủ bù đắp nhu cầu đầu tư.', 'Hàng tồn kho tăng mạnh từ 21,7 tỷ lên 367,9 tỷ VND, chủ yếu là vật liệu xây dựng cho Dự án Thủy điện Thượng Kon Tum. Dự án này đang trong quá trình xây dựng, có thể bị ứ đọng nếu tiến độ thi công chậm. Tuy nhiên, đây là dự án trọng điểm của công ty.', 5, 'Công ty hoạt động trong lĩnh vực thủy điện với doanh thu và lợi nhuận giảm so với năm trước do điều chỉnh doanh thu bán điện. Nợ vay tăng mạnh để đầu tư dự án Thượng Kon Tum, tiềm ẩn rủi ro tài chính và áp lực trả nợ lớn. Dòng tiền hoạt động kinh doanh dương nhưng không đủ bù đắp đầu tư. Triển vọng phụ thuộc vào tiến độ hoàn thành dự án Thượng Kon Tum và chính sách giá điện.'),
('VSI_2025_consolidated', 'VSI', 2025, 'consolidated', 'Doanh nghiệp có giao dịch thường xuyên với công ty mẹ và các công ty cùng mẹ, bao gồm cho thuê văn phòng, cung cấp dịch vụ, mua bán vật tư. Giá trị giao dịch không lớn so với tổng tài sản, nhưng cần giám sát tính công bằng về giá. Có khoản phải thu lớn từ công ty mẹ (6.2 tỷ VND), tiềm ẩn rủi ro về khả năng thu hồi.', 'Tổng nợ vay khoảng 87 tỷ VND, với tài sản thế chấp là bất động sản và quyền sử dụng đất. Áp lực nợ vay trung hạn, nhưng dòng tiền từ hoạt động kinh doanh khả quan. Tuy nhiên, nợ phải trả ngắn hạn lớn, cần theo dõi thanh khoản.', 'Hàng tồn kho chủ yếu là nguyên liệu và chi phí xây dựng dở dang. Dự án khu phức hợp Quận 9 bị tạm ngưng do vướng mắc, có thể dẫn đến ứ đọng vốn và giảm giá trị.', 5, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận năm 2025, với doanh thu tăng 127.55%. Tuy nhiên, cơ cấu nợ cao, đặc biệt nợ phải trả ngắn hạn chiếm tỷ trọng lớn. Các giao dịch bên liên quan存在一定 rủi ro nhưng trong tầm kiểm soát. Triển vọng phụ thuộc vào tiến độ thi công và thu hồi công nợ.'),
('VSI_2024_parent', 'VSI', 2024, 'parent', 'Công ty có mối quan hệ tập đoàn phức tạp với công ty mẹ Viwaseen và nhiều công ty cùng công ty mẹ (Viwaseen 11, Viwaseen 14). Tổng giá trị giao dịch với bên liên quan trong năm lớn, bao gồm: mua bán vật tư, cho thuê văn phòng, thi công công trình, chuyển tiền giữa các đơn vị. Số dư phải thu từ bên liên quan cuối năm đạt 12.09 tỷ VNĐ (tăng mạnh từ 1.4 tỷ đầu năm), trong đó phải thu từ Viwaseen (công ty mẹ) là 6.96 tỷ và Viwaseen 14 là 5.13 tỷ. Ngoài ra, công ty có khoản đầu tư vào công ty con Rạch Giá với dự phòng 21.6 tỷ và nhiều khoản đầu tư khác chưa thu thập được BCTC để đánh giá dự phòng. Các giao dịch này tuy phổ biến trong mô hình tập đoàn nhưng cần theo dõi rủi ro tập trung công nợ.', 'Nợ vay ngắn hạn cuối năm 10.53 tỷ VNĐ (giảm từ 14.07 tỷ đầu năm) tại VietinBank CN1, được đảm bảo bằng bất động sản. Nợ vay dài hạn đã được trả hết trong năm (từ 15.53 tỷ giảm về 0), tổng tiền trả nợ gốc vay trong năm là 39.15 tỷ. Tổng nợ phải trả 236 tỷ so với VCSH 198 tỷ, tỷ lệ nợ/vốn ~1.19. Công ty có dòng tiền hoạt động kinh doanh dương 51.9 tỷ và tiền gửi tương đương tiền cuối kỳ 97.45 tỷ, cho thấy khả năng thanh toán nợ ngắn hạn tương đối tốt. Tuy nhiên, doanh thu xây lắp giảm mạnh 50% so với năm trước đặt ra thách thức về dòng tiền tương lai.', 'Hàng tồn kho tăng mạnh 117% từ 14.0 tỷ lên 30.5 tỷ VNĐ, trong đó chi phí SXKD dở dang chiếm phần lớn (29.5 tỷ), phản ánh nhiều công trình xây dựng đang triển khai dở dang. Dự phòng giảm giá hàng tồn kho giữ nguyên ở 376 triệu. Tài sản dở dang dài hạn 17.8 tỷ, chủ yếu là dự án khu phức hợp Quận 9 (16.7 tỷ). Do doanh thu xây lắp giảm 50% trong năm 2024 do khó khăn chung ngành xây dựng, rủi ro ứ đọng hàng tồn kho và tài sản dở dang là đáng kể, đặc biệt với dự án Quận 9 đã kéo dài nhiều năm.', 5, 'WASECO là doanh nghiệp xây dựng cấp thoát nước có lịch sử lâu đời, vốn điều lệ 132 tỷ. Năm 2024, doanh thu giảm mạnh 50% do khó khăn chung ngành xây dựng, lợi nhuận sau thuế giảm từ 27.6 tỷ xuống 25.7 tỷ. Điểm tích cực: công ty đã trả hết nợ dài hạn, dòng tiền hoạt động kinh doanh dương 51.9 tỷ, tiền và tương đương tiền đạt 97.5 tỷ. Điểm rủi ro: doanh thu xây lắp sụt giảm, hàng tồn kho dở dang tăng mạnh, giao dịch với bên liên quan phức tạp trong hệ sinh thái Viwaseen, khoản đầu tư vào công ty con có dự phòng lớn. Công ty có nguồn thu ổn định từ cho thuê văn phòng (95.7 tỷ) và kinh doanh vật tư (30.1 tỷ) bù đắp phần nào sụt giảm xây lắp. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần.'),
('VSI_2025_parent', 'VSI', 2025, 'parent', 'Công ty có giao dịch thường xuyên với công ty mẹ Viwaseen và các công ty cùng mẹ bao gồm cho thuê VP, bán vật tư, thi công xây dựng. Dư nợ phải thu từ bên liên quan cuối kỳ là 6,77 tỷ VNĐ, giảm từ 12,09 tỷ đầu kỳ, cho thấy tiến độ thu hồi tích cực. Các giao dịch chủ yếu mang tính thương mại bình thường. Tuy nhiên, cần lưu ý rủi ro từ khoản đầu tư vào công ty con (Cty Mê Kông Rạch Giá) có dự phòng 20,97 tỷ VNĐ, phản ánh hiệu quả hoạt động chưa cao của công ty con này.', 'Nợ vay ngắn hạn cuối kỳ chỉ 10,75 tỷ VNĐ, hoàn toàn nằm trong tầm kiểm soát với tiền mặt cuối kỳ 130,45 tỷ VNĐ. Hạn mức tín dụng tại BIDV lên đến 94 tỷ và Vietinbank 40 tỷ, cho thấy room vay còn rất lớn. Các khoản vay được đảm bảo bằng bất động sản có giá trị ghi sổ cao (tài sản thế chấp trị giá trên 148,6 tỷ VNĐ). Không có nợ dài hạn. Áp lực nợ vay thấp.', 'Hàng tồn kho cuối kỳ 35,68 tỷ VNĐ, tăng 17% so đầu kỳ, chủ yếu do chi phí SXKD dở dang tăng (34,85 tỷ). Dự án khu phức hợp Quận 9 trị giá 15,85 tỷ đang bị tạm ngưng do vướng mắc - đây là rủi ro tiềm ẩn nếu dự án không được khôi phục. Dự phòng giảm giá hàng tồn kho chỉ 361 triệu (hơn 1 tỷ nguyên liệu), mức thấp cho thấy chất lượng tồn kho nhìn chung được kiểm soát.', 4, 'WASECO có kết quả kinh doanh tăng trưởng mạnh với doanh thu thuần tăng 151,8% đạt 545,58 tỷ VNĐ, lợi nhuận sau thuế đạt 36,87 tỷ (tăng 43,4%). Biên lợi nhuận gộp 13,12% phản ánh đặc thù ngành xây dựng. Tiền mặt dồi dào 130,45 tỷ VNĐ, nợ vay thấp chỉ 10,75 tỷ. Tuy nhiên, tồn tại một số rủi ro: (1) Dự án Quận 9 bị gián đoạn, (2) Tranh chấp pháp lý với Cty An Xuân Thịnh kéo dài từ 2020, (3) Các khoản phải thu khó đòi đã trích lập dự phòng 16,98 tỷ. Công ty có hệ thống quản trị với HĐQT 5 thành viên (có 1 thành viên độc lập) và Ban kiểm soát hoạt động. Tổng thể doanh nghiệp có sức khỏe tài chính tốt, triển vọng tích cực trong trung hạn.'),
('VSI_2024_consolidated', 'VSI', 2024, 'consolidated', 'Công ty có nhiều giao dịch lớn với công ty mẹ (Viwaseen) và các công ty cùng mẹ (Viwaseen 11, Viwaseen 14) bao gồm cho thuê văn phòng, bán vật tư, thi công công trình. Giá trị giao dịch đáng kể (hàng nghìn tỷ đồng). Có khoản phải thu từ công ty mẹ 6,96 tỷ đồng và phải trả cho công ty mẹ 230 triệu đồng. Không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn, nhưng mức độ tập trung giao dịch với bên liên quan cao.', 'Tổng nợ vay khoảng 103,7 tỷ VNĐ (ngắn hạn 10,5 tỷ, dài hạn 93,2 tỷ). Tài sản thế chấp chủ yếu là bất động sản (văn phòng, đất đai) và tài sản hình thành trong tương lai. Dòng tiền từ hoạt động kinh doanh năm 2024 dương 67,4 tỷ VNĐ đủ để trang trải nợ ngắn hạn. Tuy nhiên, doanh thu giảm mạnh 45,87% so với năm trước có thể ảnh hưởng đến khả năng trả nợ trong dài hạn nếu xu hướng giảm tiếp tục.', 'Hàng tồn kho tăng mạnh từ 14,4 tỷ lên 30,9 tỷ VNĐ, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng (từ 12,9 tỷ lên 29,6 tỷ). Có dự phòng giảm giá hàng tồn kho 376 triệu VNĐ. Tài sản dở dang dài hạn (xây dựng cơ bản dở dang) trị giá 21,5 tỷ VNĐ, bao gồm nhiều dự án đầu tư. Rủi ro ứ đọng tồn kho dở dang và dự án xây dựng dở dang ở mức trung bình do giá trị không quá lớn so với tổng tài sản.', 5, 'WASECO là doanh nghiệp xây dựng và cấp thoát nước có vốn điều lệ 132 tỷ VNĐ, hoạt động đa ngành. Năm 2024, doanh thu giảm mạnh 45,87% do khó khăn chung ngành xây dựng, nhưng lợi nhuận gộp vẫn đạt 72,8 tỷ VNĐ (tỷ suất lợi nhuận gộp 28,9%). Dòng tiền hoạt động kinh doanh dương 67,4 tỷ VNĐ. Công ty có giao dịch lớn với công ty mẹ và công ty con, nợ vay ở mức trung bình với tài sản thế chấp là bất động sản. Rủi ro chính là sự phụ thuộc vào bên liên quan và áp lực từ việc doanh thu sụt giảm. Điểm rủi ro quản trị trung bình (5/10) do cấu trúc tập đoàn và giao dịch nội bộ.'),
('VSI_2023_consolidated', 'VSI', 2023, 'consolidated', 'Công ty có nhiều giao dịch lớn với công ty mẹ (Viwaseen) và công ty cùng công ty mẹ (Công ty CP Khoan và Xây Lắp Cấp Thoát Nước), bao gồm mua bán vật tư, thi công xây dựng, cho thuê văn phòng. Các giao dịch này có giá trị lớn và diễn ra thường xuyên, nhưng không có dấu hiệu bất thường rõ ràng về giá cả hay điều kiện thanh toán. Tuy nhiên, cần giám sát chặt chẽ để tránh xung đột lợi ích.', 'Tổng nợ vay và thuê tài chính là 135.809.347.588 VNĐ, chiếm tỷ trọng đáng kể trong tổng nguồn vốn. Nợ dài hạn chủ yếu từ Ngân hàng TMCP Công Thương Việt Nam với lãi suất cao (11%/năm và lãi suất điều chỉnh) và thời hạn vay dài (72-144 tháng). Công ty đã thế chấp nhiều tài sản giá trị lớn (bất động sản đầu tư, quyền sử dụng đất, nhà xưởng) để đảm bảo cho các khoản vay. Áp lực trả nợ lãi và gốc là đáng kể, đặc biệt trong bối cảnh chi phí tài chính chiếm tỷ trọng cao trong cơ cấu chi phí.', 'Hàng tồn kho tăng từ 12.382.558.201 VNĐ lên 14.400.983.434 VNĐ, chủ yếu do tăng chi phí sản xuất kinh doanh dở dang. Dự án xây dựng cơ bản dở dang tăng mạnh từ 14.117.766.272 VNĐ lên 19.596.582.666 VNĐ, phản ánh hoạt động đầu tư xây dựng đang triển khai tích cực, đặc biệt là dự án Nhà máy nước Nam Rạch Giá. Dự phòng giảm giá hàng tồn kho không thay đổi (376.284.412 VNĐ). Rủi ro tồn kho ở mức kiểm soát được, nhưng cần theo dõi tiến độ thi công và khả năng hoàn thành các dự án.', 4, 'Công ty đạt kết quả kinh doanh tích cực trong năm 2023 với doanh thu thuần tăng 38% và lợi nhuận sau thuế tăng 8%. Dòng tiền từ hoạt động kinh doanh dương và tăng trưởng. Tuy nhiên, công ty đối mặt với áp lực nợ vay lớn với chi phí lãi vay cao (18 tỷ VNĐ). Các giao dịch với bên liên quan diễn ra phức tạp, đòi hỏi sự minh bạch và giám sát chặt chẽ. Công ty có tài sản đảm bảo tốt nhưng đòn bẩy tài chính ở mức cao. Triển vọng phụ thuộc vào khả năng thu hồi công nợ, quản lý chi phí và tiến độ thực hiện các dự án xây dựng lớn.'),
('VTA_2019_consolidated', 'VTA', 2019, 'consolidated', 'Công ty có nhiều giao dịch mua bán hàng hóa với các bên liên quan trong cùng hệ thống với giá trị lớn, đặc biệt là giao dịch bán hàng cho Công ty TNHH MTV Kinh doanh sản phẩm Fico lên tới gần 77 tỷ VND trong năm 2019. Ngoài ra, có khoản vay từ Tổng Công ty Vật liệu Xây dựng Số 1 - CTCP với lãi suất ưu đãi 0.2%/tháng, thấp hơn nhiều so với lãi suất thị trường. Các giao dịch này có thể tiềm ẩn rủi ro về giá chuyển nhượng và tính minh bạch.', 'Áp lực nợ vay ở mức cao với tổng nợ vay ngắn hạn và dài hạn là 53.4 tỷ VND, chiếm tỷ trọng lớn trong cơ cấu nguồn vốn. Công ty chủ yếu phụ thuộc vào vay ngân hàng và vay từ công ty mẹ. Khả năng thanh toán nợ ngắn hạn bị ảnh hưởng bởi dòng tiền hoạt động kinh doanh giảm mạnh so với năm trước. Tài sản thế chấp chủ yếu là bất động sản và máy móc thiết bị.', 'Giá trị hàng tồn kho tăng mạnh từ 65.9 tỷ lên 86.5 tỷ VND, trong đó thành phẩm chiếm tỷ trọng lớn và đã trích lập dự phòng giảm giá 7.7 tỷ VND. Chi phí xây dựng cơ bản dở dang giảm nhẹ nhưng vẫn ở mức cao (17 tỷ VND), cho thấy một số dự án đầu tư có thể bị chậm tiến độ.', 7, 'Sức khỏe tài chính của Công ty Cổ phần Vitaly đang đối mặt với nhiều thách thức: doanh thu và lợi nhuận sau thuế giảm mạnh lần lượt 23% và 32% so với năm trước; áp lực nợ vay cao với tỷ lệ nợ/vốn chủ sở hữu xấp xỉ 2; dòng tiền từ hoạt động kinh doanh giảm sút. Công ty có nhiều giao dịch với các bên liên quan trong hệ thống, tiềm ẩn rủi ro về quản trị. Triển vọng đầu tư tiêu cực trong ngắn hạn do ngành xây dựng vật liệu chịu áp lực cạnh tranh lớn.'),
('VSI_2022_consolidated', 'VSI', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch thương mại bình thường như cho thuê văn phòng, mua bán hàng hóa, thanh toán công trình xây dựng. Không có dấu hiệu bất thường đáng kể về giá cả hay điều kiện giao dịch.', 'Công ty có tổng nợ vay khoảng 166.8 tỷ VNĐ, chủ yếu là vay dài hạn (156 tỷ) với lãi suất cố định và điều chỉnh từ 8-11%/năm. Nợ vay được đảm bảo bằng bất động sản đầu tư và quyền sử dụng đất. Áp lực trả nợ trung bình do có tài sản thế chấp đầy đủ nhưng tỷ lệ nợ/vốn chủ sở hữu cao.', 'Hàng tồn kho có dự phòng giảm giá 376 triệu VNĐ, chủ yếu là nguyên vật liệu. Dự án xây dựng dở dang có giá trị lớn (14.1 tỷ VNĐ), cần theo dõi tiến độ triển khai và khả năng thu hồi vốn.', 5, 'Công ty có doanh thu tăng trưởng 31.2% so với năm trước nhưng lợi nhuận sau thuế giảm 51.9% do chi phí tài chính tăng. Cơ cấu tài sản và nguồn vốn tương đối cân đối. Có một số rủi ro về nợ vay, tồn kho và dự án dở dang. Triển vọng kinh doanh phụ thuộc vào tiến độ các dự án xây dựng và khả năng thu hồi công nợ.'),
('VSI_2023_parent', 'VSI', 2023, 'parent', 'Công ty có giao dịch lớn với công ty mẹ Viwaseen và công ty cùng công ty mẹ (Công ty CP Khoan và Xây Lắp Cấp Thoát Nước) với tổng giá trị giao dịch lên đến hàng trăm tỷ đồng, bao gồm mua bán vật tư, cho thuê văn phòng, và thực hiện các hợp đồng xây dựng theo hình thức liên danh. Các giao dịch liên danh thi công xây dựng với công ty mẹ chiếm tỷ trọng lớn trong doanh thu (xuất hóa đơn 27.7 tỷ cho gói thầu Tam Phước). Số dư công nợ phải thu từ Viwaseen cuối kỳ là 1.4 tỷ và phải trả cho Viwaseen 11 là 8.5 tỷ. Cần lưu ý tính công bằng của giá cả trong các giao dịch liên kết này.', 'Tổng nợ vay tài chính khoảng 29.6 tỷ VNĐ (ngắn hạn 14.07 tỷ với lãi suất 6.5%/năm và dài hạn 15.53 tỷ với lãi suất 11%/năm). Nợ dài hạn phục vụ đầu tư dự án bất động sản Trung tâm trưng bày vật tư với kỳ hạn 138 tháng. Công ty có tài sản thế chấp lớn: bất động sản đầu tư trị giá sổ sách 121.6 tỷ đã dùng thế chấp, tòa nhà văn phòng khu A, và cầm cố giấy tờ có giá 10 tỷ. Chi phí lãi vay năm 2023 là 4.87 tỷ (giảm so với năm trước 7.26 tỷ). Áp lực nợ ở mức trung bình.', 'Hàng tồn kho tăng từ 11.48 tỷ lên 14.03 tỷ, chủ yếu do tăng chi phí SXKD dở dang (12.88 tỷ). Dự án khu phức hợp Quận 9 chiếm 14 tỷ trong tài sản dở dang dài hạn - đây là dự án bất động sản có thể chịu ảnh hưởng từ biến động thị trường bất động sản. Công ty đã trích lập dự phòng giảm giá hàng tồn kho 376 triệu cho nguyên liệu vật liệu. Dự án Quận 9 chưa có dự phòng đánh giá lại, cần theo dõi tiến độ triển khai.', 5, 'Công ty WASECO có kết quả kinh doanh tích cực năm 2023 với doanh thu tăng 43.1% (từ 304.5 tỷ lên 435.7 tỷ VNĐ) và lợi nhuận sau thuế tăng 10.4% (từ 25.03 tỷ lên 27.63 tỷ VNĐ). Tuy nhiên, biên lợi nhuận gộp giảm từ 18.2% xuống 13.7% do giá vốn tăng nhanh hơn doanh thu. Dòng tiền hoạt động kinh doanh dương 52.6 tỷ, tăng so với năm trước. Công ty có cơ cấu tài sản với bất động sản đầu tư lớn (121.6 tỷ) và đầu tư vào công ty con (68.97 tỷ, dự phòng 25.37 tỷ). Rủi ro chính: giao dịch với bên liên quan lớn và phức tạp; khoản phải thu khó đòi từ Công ty CP XD TM An Xuân Thịnh (8.99 tỷ) đang trong quá trình giám đốc thẩm; biên lợi nhuận có xu hướng giảm. Công ty đã chi trả cổ tức 26.4 tỷ trong năm 2023.'),
('VSI_2021_consolidated', 'VSI', 2021, 'consolidated', 'Công ty có giao dịch với công ty mẹ Viwaseen, bao gồm cho vay không lãi suất và các khoản chuyển tiền, có thể gây rủi ro về giao dịch không theo giá thị trường.', 'Nợ vay dài hạn chiếm tỷ trọng cao với lãi suất cố định 11% và lãi suất điều chỉnh, được đảm bảo bằng bất động sản và tài sản hình thành trong tương lai. Áp lực trả nợ trung bình.', 'Hàng tồn kho có dự phòng giảm giá cho nguyên liệu, nhưng chi phí xây dựng dở dang lớn, có thể rủi ro chậm tiến độ hoặc tăng chi phí.', 6, 'Công ty có kết quả kinh doanh khả quan với lợi nhuận tăng, nhưng nợ vay cao và giao dịch bên liên quan cần được giám sát. Triển vọng phụ thuộc vào tiến độ dự án và quản lý dòng tiền.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSI_2021_parent', 'VSI', 2021, 'parent', 'Công ty có giao dịch với bên liên quan là công ty mẹ và công ty con, bao gồm cho thuê, chuyển tiền và cho vay. Các giao dịch này có vẻ bình thường và không có dấu hiệu bất thường, nhưng cần theo dõi khả năng thanh toán của công ty mẹ.', 'Công ty có nợ vay ngân hàng với lãi suất cố định, tài sản thế chấp đủ để đảm bảo. Tuy nhiên, áp lực nợ dài hạn có thể cao với lãi suất 11%/năm.', 'Hàng tồn kho bao gồm nguyên liệu và chi phí dở dang, có dự phòng giảm giá cho nguyên liệu. Các dự án xây dựng dở dang cần được theo dõi tiến độ để tránh ứ đọng.', 3, 'Công ty có sức khỏe tài chính ổn định với lợi nhuận tăng trưởng, nhưng cần quản lý rủi ro nợ và tiến độ dự án. Triển vọng đầu tư trung bình.'),
('VSI_2019_consolidated', 'VSI', 2019, 'consolidated', 'Giao dịch với công ty mẹ Viwaseen chủ yếu là thanh toán hợp đồng xây dựng và cho thuê văn phòng, không có dấu hiệu bất thường rõ ràng về giá hay điều kiện thanh toán.', 'Nợ vay dài hạn chiếm tỷ trọng lớn, chủ yếu vay đầu tư dự án với lãi suất cố định và điều chỉnh, tài sản thế chấp là bất động sản và quyền sử dụng đất. Áp lực trả nợ có nhưng được đảm bảo bằng tài sản.', 'Hàng tồn kho giảm mạnh so với đầu năm do dự án khu phức hợp Q9 đã hoàn thành và chuyển giao. Dự án xây dựng dở dang còn nhiều, trong đó dự án NMN Nam Rạch Giá và dự án 158/16 Bình Quới có giá trị lớn, cần theo dõi tiến độ và khả năng thu hồi vốn.', 5, 'Công ty có quy mô tài sản và doanh thu lớn, tập trung trong lĩnh vực xây dựng cấp thoát nước. Lợi nhuận gộp ở mức trung bình. Nợ vay chiếm tỷ trọng cao nhưng có tài sản đảm bảo. Giao dịch với công ty mẹ có tính thương mại, không phức tạp. Điểm rủi ro quản trị ở mức trung bình do có giao dịch bên liên quan lớn nhưng minh bạch.'),
('VSI_2019_parent', 'VSI', 2019, 'parent', 'Công ty có giao dịch lớn với công ty mẹ (Viwaseen) và công ty con, bao gồm cho thuê văn phòng, thanh toán hợp đồng, và mua bán hàng hóa. Giá trị giao dịch cao, nhưng không có bằng chứng về giao dịch bất thường như cho vay không lãi suất. Mối quan hệ thương mại là truyền thống và cần theo dõi.', 'Áp lực nợ vay đáng kể với tổng nợ vay khoảng 90 tỷ VNĐ, trong đó nợ dài hạn chiếm phần lớn. Công ty đã thế chấp tài sản bất động sản và tương lai để đảm bảo vay. Lãi vay tăng mạnh, ảnh hưởng đến lợi nhuận. Cần theo dõi khả năng thanh toán từ dòng tiền hoạt động.', 'Hàng tồn kho giảm mạnh so với đầu năm, có dự phòng giảm giá 376 triệu VNĐ. Các dự án xây dựng dở dang có giá trị lớn, tiềm ẩn rủi ro chậm tiến độ và chi phí tăng cao. Dự án khu phức hợp Q.9 đã hoàn thành giá trị cuối năm, nhưng dự án khác vẫn đang triển khai.', 6, 'Công ty có tình hình tài chính ổn định với doanh thu và lợi nhuận tăng nhẹ. Tuy nhiên, áp lực nợ vay và chi phí lãi vay tăng cao, cần quản lý rủi ro thanh khoản. Giao dịch với các bên liên quan lớn nhưng không bất thường. Triển vọng kinh doanh phụ thuộc vào tiến độ dự án và thu hồi công nợ.'),
('VSI_2020_parent', 'VSI', 2020, 'parent', 'Giao dịch với các bên liên quan diễn ra thường xuyên và có vẻ bình thường, không có dấu hiệu bất thường như cho vay không lãi suất hay giao dịch chênh lệch lớn.', 'Nợ vay có lãi suất cố định, tài sản thế chấp đủ để đảm bảo, áp lực thanh toán nợ ở mức trung bình.', 'Hàng tồn kho dở dang và dự án xây dựng không có dấu hiệu ứ đọng, dự phòng giảm giá hàng tồn kho thấp.', 5, 'Công ty có tình hình tài chính ổn định, lợi nhuận giảm trong năm 2020 do ảnh hưởng của dịch bệnh, nhưng vẫn duy trì hoạt động kinh doanh liên tục và có triển vọng trong lĩnh vực cấp thoát nước.'),
('VSI_2018_parent', 'VSI', 2018, 'parent', 'Công ty có giao dịch lớn với công ty mẹ Viwaseen với tổng giá trị giao dịch trong năm hơn 100 tỷ VNĐ, bao gồm cung cấp dịch vụ, xuất hóa đơn, ứng tiền và nợ phải trả lãi chậm thanh toán. Phải trả nội bộ dài hạn cho Viwaseen tăng mạnh từ 10.8 triệu lên 5.6 tỷ VNĐ. Công ty cũng có giao dịch với các công ty con (Địa Lợi, Đông Nam Á Mêkông) với giá trị phải thu hơn 6.6 tỷ VNĐ. Các giao dịch này có mức độ tập trung cao, tuy nhiên không phát hiện dấu hiệu bất thường rõ ràng về giá hay điều kiện giao dịch.', 'Nợ vay dài hạn tăng mạnh từ 25.6 tỷ lên 60.4 tỷ VNĐ (+136%), chủ yếu từ khoản vay tại Vietinbank để đầu tư hai dự án lớn (nhà máy nước Đắk Mil và Trung tâm trưng bày vật tư khu C). Lãi suất vay dao động 7.8%-9.0%/năm. Công ty đã thế chấp bất động sản đầu tư trị giá hơn 60.7 tỷ và bất động sản hình thành trong tương lai trị giá 134.5 tỷ. Chi phí lãi vay tăng từ 1.67 tỷ lên 3.40 tỷ VNĐ. Áp lực trả nợ trong trung hạn là đáng kể khi dòng tiền hoạt động kinh doanh chỉ đạt 28.2 tỷ.', 'Hàng tồn kho tăng mạnh từ 12.5 tỷ lên 58.7 tỷ VNĐ (+367%), chủ yếu do chi phí xây dựng cơ bản dở dang tăng từ 10.4 tỷ lên 56.6 tỷ VNĐ. Dự án lớn nhất là Trung tâm trưng bày vật tư khu C trị giá 86.6 tỷ. Dự phòng giảm giá hàng tồn kho chỉ 376 triệu (cho nguyên liệu vật liệu), mức thấp so với quy mô tồn kho. Rủi ro ứ đọng tài sản dở dang là đáng lưu ý khi nhiều dự án đang trong giai đoạn triển khai.', 4, 'WASECO ghi nhận tăng trưởng doanh thu ấn tượng 36.8% (từ 380.9 tỷ lên 521.3 tỷ VNĐ), lợi nhuận gộp tăng 13.6%, lợi nhuận sau thuế đạt 31.2 tỷ VNĐ. Tuy nhiên, công ty đang trong giai đoạn đầu tư mở rộng mạnh với nợ vay tăng gấp rưỡi và tài sản dở dang tăng gần 4 lần. Dòng tiền từ hoạt động kinh doanh dương 28.2 tỷ nhưng không đủ bù đắp nhu cầu đầu tư 34.7 tỷ. Tỷ suất lợi nhuận gộp giảm từ 12.3% xuống 10.2% cho thấy biên lợi nhuận bị nén. Công ty có cơ cấu sở hữu tập trung với công ty mẹ Viwaseen nắm giữ 60% vốn và có nhiều giao dịch nội bộ. Triển vọng phụ thuộc vào tiến độ và hiệu quả của các dự án đầu tư lớn đang triển khai.'),
('VSI_2018_consolidated', 'VSI', 2018, 'consolidated', 'Công ty có mối quan hệ phức tạp với công ty mẹ Tổng Công ty Đầu tư Nước và Môi trường Việt Nam (Viwaseen) với nhiều loại giao dịch đa dạng. Tổng giá trị giao dịch trong năm 2018 rất lớn: Waseco xuất hóa đơn cho Viwaseen 52,7 tỷ VNĐ, Viwaseen chuyển tiền cho Waseco 35,8 tỷ VNĐ, Viwaseen cung cấp vật tư 13 tỷ VNĐ. Số dư phải trả nội bộ với Viwaseen cuối kỳ lên đến 5,6 tỷ VNĐ (tăng đột biến từ 10,8 triệu VNĐ đầu kỳ), ngoài ra còn có khoản người mua trả trước từ Viwaseen 5 tỷ VNĐ. Các giao dịch này có tính chất luân chuyển tiền lớn giữa công ty mẹ và công ty con, cần được giám sát chặt chẽ để đảm bảo tính minh bạch và công bằng cho cổ đông thiểu số.', 'Tổng nợ vay tài chính cuối kỳ đạt 186,5 tỷ VNĐ, trong đó nợ dài hạn chiếm phần lớn (176,2 tỷ VNĐ). Chi phí lãi vay tăng đột biến từ 1,67 tỷ VNĐ năm 2017 lên 13,04 tỷ VNĐ năm 2018 (tăng gần 7 lần), phản ánh áp lực tài chính rất lớn từ hoạt động đầu tư mở rộng. Các khoản vay dài hạn chủ yếu từ Vietinbank với lãi suất 9%/năm hoặc lãi suất điều chỉnh, phục vụ cho 3 dự án lớn: nhà máy nước Đắk Mil, dự án khu C và dự án cấp nước Nam Rạch Giá. Tài sản thế chấp bao gồm bất động sản hình thành trong tương lai, quyền sử dụng đất và nhiều tài sản cố định có giá trị ghi sổ hàng trăm tỷ VNĐ. Tỷ lệ nợ phải trả trên tổng tài sản đạt 70% cho thấy đòn bẩy tài chính cao.', 'Hàng tồn kho tăng mạnh từ 14,3 tỷ VNĐ lên 60,7 tỷ VNĐ (tăng 324%), chủ yếu do chi phí sản xuất kinh doanh dở dang tăng từ 10,9 tỷ lên 57,1 tỷ VNĐ, phản ánh số lượng hợp đồng xây dựng đang triển khai lớn. Dự phòng giảm giá hàng tồn kho chỉ 376 triệu VNĐ cho nguyên liệu vật liệu, mức dự phòng này có thể chưa đầy đủ. Các dự án xây dựng cơ bản dở dang có giá trị 110,4 tỷ VNĐ, bao gồm dự án khu C trị giá 86,6 tỷ VNĐ và dự án 158/16 Bình Quới 15,7 tỷ VNĐ. Tồn kho và dự án dở dang chiếm tỷ trọng lớn trong tài sản ngắn hạn và dài hạn, tiềm ẩn rủi ro ứ đọng vốn nếu tiến độ thi công bị chậm trễ.', 6, 'Công ty WASECO ghi nhận tăng trưởng doanh thu ấn tượng 52% (từ 349 tỷ lên 532 tỷ VNĐ) nhờ mở rộng hoạt động thi công xây lắp và kinh doanh vật tư. Tuy nhiên, lợi nhuận sau thuế của công ty mẹ giảm 25% (từ 31 tỷ xuống 23 tỷ VNĐ) do chi phí lãi vay tăng vọt 681% phản ánh hoạt động đầu tư mở rộng quy mô bằng vốn vay. Cơ cấu tài chính có nhiều điểm đáng lo ngại: tỷ lệ nợ phải trả/tổng tài sản 70%, hàng tồn kho tăng 324%, phải thu khách hàng tăng 85%. Các điểm tích cực bao gồm: doanh thu tăng trưởng mạnh, dòng tiền từ hoạt động kinh doanh dương 5,2 tỷ VNĐ (so với âm 99,7 tỷ năm trước), các khoản phải thu chủ yếu từ các công ty cấp nước lớn có uy tín. Công ty đang trong giai đoạn mở rộng đầu tư mạnh vào bất động sản và hạ tầng cấp nước, cần theo dõi sát tiến độ các dự án lớn và khả năng tạo dòng tiền để trả nợ. Điểm rủi ro quản trị ở mức trung bình do giao dịch bên liên quan phức tạp với công ty mẹ, nợ vay lớn với nhiều tài sản thế chấp, và hàng tồn kho/dự án dở dang chiếm tỷ trọng cao.'),
('VSI_2017_consolidated', 'VSI', 2017, 'consolidated', 'Công ty có giao dịch với công ty mẹ và công ty con, bao gồm cho vay, trả lãi vay và góp vốn. Giao dịch với công ty con có giá trị lớn, tuy nhiên, mối quan hệ là bình thường và không có dấu hiệu bất thường rõ ràng. Rủi ro ở mức trung bình.', 'Tổng nợ vay khoảng 1500 tỷ VNĐ, trong đó nợ dài hạn chiếm tỷ trọng lớn, được đảm bảo bằng tài sản thế chấp như quyền sử dụng đất và tài sản hình thành trong tương lai. Áp lực nợ vay cao nhưng công ty có dòng tiền từ hoạt động kinh doanh và tài sản tài chính để đáp ứng nghĩa vụ.', 'Hàng tồn kho có dự phòng giảm giá, nhưng giá trị không quá lớn. Các dự án xây dựng dở dang có giá trị lớn, tiềm ẩn rủi ro về tiến độ thi công và chi phí phát sinh.', 6, 'Công ty có doanh thu và lợi nhuận tăng trưởng tốt, tỷ lệ lợi nhuận gộp ổn định. Tuy nhiên, nợ vay cao và nhiều dự án xây dựng dở dang đòi hỏi quản lý rủi ro chặt chẽ. Giao dịch với các bên liên quan là bình thường. Triển vọng đầu tư trung bình, cần theo dõi tiến độ dự án và khả năng trả nợ.'),
('VSI_2017_parent', 'VSI', 2017, 'parent', 'Công ty có các giao dịch với công ty mẹ (Viwaseen) và công ty con (Công ty CP TV & Cấp nước Đông Nam Á Mêkông - Rạch Giá), bao gồm cho vay, góp vốn, và dịch vụ xây dựng. Các giao dịch này có vẻ bình thường trong mối quan hệ tập đoàn, không có dấu hiệu bất thường rõ ràng.', 'Nợ vay tăng từ 24.2 tỷ VND (đầu năm) lên 52.8 tỷ VND (cuối năm), trong đó nợ ngắn hạn tăng từ 17.2 tỷ lên 27.2 tỷ VND và nợ dài hạn tăng từ 7.1 tỷ lên 25.6 tỷ VND. Công ty đã thế chấp tài sản đáng kể (như bất động sản) cho các khoản vay. Áp lực trả nợ có thể tăng, nhưng dòng tiền từ hoạt động kinh doanh vẫn dương.', 'Hàng tồn kho giảm từ 21.3 tỷ VND xuống 12.6 tỷ VND, và dự phòng giảm giá hàng tồn kho tăng 376 triệu VND. Xây dựng cơ bản dở dang giảm nhẹ từ 31.6 tỷ xuống 31.2 tỷ VND, nhưng vẫn ở mức cao, cho thấy một số dự án có thể bị ứ đọng.', 5, 'Công ty có tình hình tài chính ổn định với doanh thu và lợi nhuận tăng trưởng. Tuy nhiên, nợ vay tăng mạnh, đặc biệt nợ dài hạn, và tài sản thế chấp lớn. Quản trị rủi ro ở mức trung bình, không có vấn đề nghiêm trọng nhưng cần theo dõi nợ và tiến độ dự án.'),
('VSI_2016_consolidated', 'VSI', 2016, 'consolidated', 'Giao dịch với công ty mẹ bao gồm thanh toán công nợ dự án, tiền cổ tức, thuê văn phòng và lãi vay. Các giao dịch này có thể được thực hiện trên cơ sở không thị trường, đặt ra rủi ro liên quan đến sự công bằng và minh bạch.', 'Nợ vay ngắn hạn và dài hạn tổng cộng khoảng 24.9 tỷ VND, có tài sản thế chấp bao gồm bất động sản và thiết bị. Áp lực nợ vay ở mức trung bình, nhưng cần theo dõi khả năng thanh toán từ dòng tiền hoạt động kinh doanh.', 'Hàng tồn kho có giá trị 22.7 tỷ VND và tài sản dở dang dài hạn 78 tỷ VND, bao gồm nhiều dự án bất động sản và xây dựng. Rủi ro ứ đọng vốn cao nếu các dự án không được triển khai đúng tiến độ.', 6, 'Công ty có doanh thu giảm mạnh so với năm trước nhưng vẫn duy trì lợi nhuận gộp dương. Nợ vay được kiểm soát với tài sản đảm bảo, nhưng dòng tiền hoạt động kinh doanh âm. Các dự án bất động sản và xây dựng dở dang có thể tạo rủi ro tài chính nếu không được quản lý tốt. Triển vọng đầu tư phụ thuộc vào khả năng hoàn thành các dự án và thu hồi công nợ.'),
('VSI_2016_parent', 'VSI', 2016, 'parent', 'Công ty có quan hệ mật thiết với công ty mẹ Viwaseen và 2 công ty con. Có khoản nợ nội bộ dài hạn với công ty mẹ 5.6 tỷ VNĐ, trích trước lãi vay 7.1 tỷ, và đặc biệt khoản góp vốn 53.1 tỷ vào công ty con Rạch Giá trong năm. Tuy nhiên, không phát hiện giao dịch bất thường rõ ràng về lãi suất hay chênh lệch giá.', 'Tổng nợ vay 24.2 tỷ VNĐ (ngắn hạn 17.2 tỷ, dài hạn 7.1 tỷ). Tỷ lệ nợ/tổng tài sản khoảng 5.8% - mức an toàn. Tài sản thế chấp là bất động sản đầu tư 67.9 tỷ VNĐ (Nhà điều hành sản xuất và cho thuê văn phòng 13 tầng) đảm bảo đầy đủ cho các khoản vay. Áp lực nợ ở mức trung bình.', 'Tài sản dở dang dài hạn lên đến 31.6 tỷ VNĐ với nhiều dự án xây dựng đang triển khai (Q9, DakMin, Vũng Tàu). Dự án Q9 chiếm 13.1 tỷ và DakMin 11.1 tỷ. Hàng tồn kho 21.3 tỷ, trong đó chi phí SX KD dở dang chiếm 16.6 tỷ. Rủi ro ứ đọng vốn cao nếu các dự án chậm tiến độ.', 6, 'Công ty xây dựng cấp thoát nước có quy mô trung bình với tổng tài sản 417.6 tỷ VNĐ. Biên lợi nhuận gộp 20.2% ở mức khá. Tuy nhiên, dòng tiền từ hoạt động kinh doanh âm -18 tỷ do đầu tư mạnh vào dự án. Nợ phải trả chiếm 45.8% tổng tài sản. Công ty có mối quan hệ kinh doanh chặt chẽ với công ty mẹ và công ty con, đặc biệt khoản góp vốn lớn 53 tỷ vào Rạch Giá. Điểm lưu ý là khoản phải thu quá hạn trên 3 năm từ Công ty Đồng Phượng (47.9 tỷ) chỉ trích lập dự phòng 30% thay vì 100% theo quy định.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSI_2015_consolidated', 'VSI', 2015, 'consolidated', 'Giao dịch với công ty mẹ Viwaseen có quy mô lớn: thanh toán công nợ dự án Waseco Plaza 70,8 tỷ VNĐ, lãi vay nội bộ 7,1 tỷ VNĐ, cổ tức 7,9 tỷ VNĐ. Số dư nợ phải trả nội bộ dài hạn giảm mạnh từ 70,9 tỷ về 0, thay vào đó chuyển thành phải trả dài hạn khác 7,1 tỷ VNĐ. Việc thanh toán nợ lớn cho công ty mẹ trong năm có thể ảnh hưởng đến dòng tiền hoạt động. Cần lưu ý lãi suất vay nội bộ không được chi tiết công khai.', 'Nợ vay ngắn hạn giảm mạnh từ 70,6 tỷ xuống 13,6 tỷ VNĐ, phản ánh việc trả nợ tích cực. Tuy nhiên, tỷ trọng nợ vay/nguồn vốn thấp, Công ty có lượng tiền mặt và tương đương tiền 55,3 tỷ VNĐ cùng đầu tư ngắn hạn 70 tỷ VNĐ, đảm bảo khả năng thanh khoản tốt. Phải trả dài hạn khác 27 tỷ VNĐ với nhiều đối tượng khác nhau cần theo dõi. Tổng nợ phải trả 220 tỷ VNĐ trên tổng tài sản 412 tỷ VNĐ (tỷ lệ nợ ~53%), mức trung bình.', 'Hàng tồn kho giảm mạnh từ 64,9 tỷ xuống 20,4 tỷ VNĐ, chủ yếu do giảm chi phí SXKD dở dang (từ 60,7 tỷ xuống 16,1 tỷ). Tài sản dở dang dài hạn giảm rất mạnh từ 391,1 tỷ xuống 35,2 tỷ VNĐ, cho thấy dự án chung cư cao tầng 10 Phổ Quang (trị giá cũ 369,3 tỷ) đã được hoàn thành/chuyển giao. Các dự án còn lại gồm khu phức hợp Q9 (14,7 tỷ) và dự án 158/16 Bình Quới (15,7 tỷ) vẫn đang triển khai. Rủi ro tồn kho ở mức vừa phải do đã xử lý được lượng lớn dự án dở dang.', 6, 'WASECO ghi nhận kết quả kinh doanh tăng trưởng mạnh năm 2015: doanh thu thuần tăng 83% từ 338,8 tỷ lên 620 tỷ VNĐ, lợi nhuận sau thuế tăng 113% từ 14 tỷ lên 29,9 tỷ VNĐ, chủ yếu nhờ doanh thu chuyển nhượng dự án 345 tỷ VNĐ. Tuy nhiên, Công ty đối mặt với nhiều rủi ro: (1) Nợ phải thu khó đòi tăng vọt do khoản nợ 47,9 tỷ từ Công ty Đồng Phượng quá hạn trên 3 năm chỉ thu hồi được 30%; (2) Chi phí khác tăng mạnh 11,1 tỷ VNĐ do tiền phạt chậm tiến độ 5,3 tỷ và phạt chậm nộp thuế 2,7 tỷ; (3) Chi phí quản lý tăng đột biến 59,2 tỷ do trích lập dự phòng phải thu khó đòi 35,8 tỷ; (4) Giao dịch với công ty mẹ quy mô lớn. Dù vậy, Công ty có vị thế thanh khoản tốt với tiền mặt và đầu tư ngắn hạn tổng cộng 125,3 tỷ VNĐ. EPS tăng từ 1.047 lên 2.267 VNĐ/cổ phiếu. Điểm rủi ro quản trị ở mức 6/10 do có nhiều vấn đề cần theo dõi nhưng chưa đến mức nghiêm trọng.'),
('VSI_2015_parent', 'VSI', 2015, 'parent', 'Công ty có giao dịch lớn với công ty mẹ (Viwaseen) và công ty con (Địa Lợi), bao gồm thanh toán công nợ dự án Waseco Plaza 70,8 tỷ VNĐ, cho vay/trả trước 4,7 tỷ VNĐ. Các giao dịch này có thể ảnh hưởng đến tính độc lập và dòng tiền, cần theo dõi chặt chẽ.', 'Nợ vay ngắn hạn giảm mạnh từ 69,8 tỷ xuống 12,8 tỷ VNĐ, áp lực nợ giảm đáng kể. Công ty có tài sản thế chấp lớn (bất động sản đầu tư 71,5 tỷ VNĐ) đảm bảo cho các khoản vay.', 'Hàng tồn kho giảm mạnh 69% cho thấy hoạt động tiêu thụ tốt. Dự án dở dang giảm 95% có thể do đã hoàn thành hoặc thoái vốn, nhưng cần kiểm tra tiến độ và khả năng thu hồi vốn. Dự phòng phải thu khó đòi tăng vọt lên 36,9 tỷ VNĐ là rủi ro lớn.', 5, 'Sức khỏe tài chính cải thiện rõ rệt năm 2015: lợi nhuận tăng mạnh, nợ giảm, dòng tiền hoạt động kinh doanh dương lớn. Tuy nhiên, tồn tại rủi ro từ dự phòng phải thu khó đòi khổng lồ (36,9 tỷ VNĐ) và giao dịch bên liên quan phức tạp. Triển vọng trung hạn phụ thuộc vào khả năng thu hồi công nợ và hiệu quả các dự án bất động sản.'),
('VSG_2024_consolidated', 'VSG', 2024, 'consolidated', 'Công ty có khoản phải thu ngắn hạn với ông Trần Huy Vượng (Tổng Giám đốc) trị giá hơn 10 triệu VND phát sinh từ tạm ứng cá nhân. Mặc dù Công ty công bố không phát sinh giao dịch với các bên liên quan, mối quan hệ nợ nần giữa Tổng Giám đốc và công ty vẫn cần được giám sát. Ngoài ra, Công ty Cổ phần Mua bán nợ Phương Đông nắm giữ 24,90% vốn điều lệ nhưng không có giao dịch trong kỳ.', 'Rủi ro nợ vay ở mức rất cao. Toàn bộ khoản vay 283,95 tỷ VND từ Ngân hàng TMCP Hàng Hải Việt Nam đã quá hạn thanh toán. Nợ ngắn hạn lớn hơn tài sản ngắn hạn 797 tỷ VND. Chi phí lãi vay chiếm tỷ trọng lớn trong cơ cấu chi phí tài chính (21,76 tỷ VND). Công ty đang trong quá trình tái cơ cấu và phụ thuộc vào sự hỗ trợ giãn nợ từ phía ngân hàng. Công ty đã mất toàn bộ tàu thuyền kinh doanh từ tháng 2/2024.', 'Rủi ro hàng tồn kho thấp do giá trị tồn kho chỉ 553 triệu VND. Tuy nhiên, tàu Glory chờ thanh lý có giá trị hơn 11,5 tỷ VND trình bày trong chi phí trả trước ngắn hạn là khoản tài sản chưa được xử lý, ngân hàng chưa thanh lý được trong năm 2023 và 2024.', 9, 'Công ty Container Phía Nam đang trong tình trạng tài chính rất nghiêm trọng. Lỗ lũy kế 934,72 tỷ VND vượt vốn chủ sở hữu 767,52 tỷ VND. Doanh thu thuần giảm 65% so với năm trước do mất toàn bộ tàu thuyền kinh doanh. Kiểm toán viên từ chối đưa ra ý kiến do không xác nhận được tính hiện hữu và khả năng thu hồi các khoản phải thu khách hàng 208 tỷ VND. Các khoản nợ vay ngân hàng đã quá hạn thanh toán. Công ty đang tái cơ cấu và tìm kiếm phương án hoạt động mới. Triển vọng đầu tư cực kỳ rủi ro, nguy cơ phá sản cao nếu không được hỗ trợ tài chính hoặc tìm được nguồn doanh thu mới thay thế.'),
('VSG_2025_consolidated', 'VSG', 2025, 'consolidated', 'Công ty không có giao dịch bất thường với các bên liên quan ngoài việc chi trả lương và thù lao cho ban lãnh đạo.', 'Nợ vay ngắn hạn lớn, quá hạn thanh toán cả gốc và lãi. Công ty không có khả năng thanh toán đúng hạn, nợ phải trả vượt tài sản. Các khoản vay tại Ngân hàng TMCP Hàng hải Việt Nam đã quá hạn nhưng chưa thanh toán.', 'Hàng tồn kho đã trích lập dự phòng giảm giá 100%, không có rủi ro tồn kho.', 8, 'Công ty đang trong giai đoạn tái cơ cấu, lỗ lũy kế lớn, nợ vượt tài sản. Khả năng thanh toán kém, nhưng ban lãnh đạo tin tưởng vào sự hỗ trợ từ cổ đông và chủ nợ. Triển vọng đầu tư rủi ro cao.'),
('VSG_2022_consolidated', 'VSG', 2022, 'consolidated', 'Không có thông tin về giao dịch bên liên quan trong văn bản cung cấp.', 'Không có thông tin về nợ vay trong văn bản cung cấp.', 'Không có thông tin về hàng tồn kho trong văn bản cung cấp.', 5, 'Văn bản cung cấp là hợp đồng dịch vụ kiểm toán giữa Công ty Cổ phần Container Phía Nam và Công ty TNHH Kiểm toán và Tư vấn A&C cho năm tài chính 2022. Không có thông tin tài chính chi tiết về công ty, do đó không thể đánh giá đầy đủ sức khỏe tài chính. Hợp đồng cho thấy công ty đang tiến hành kiểm toán độc lập theo quy định, đây là tín hiệu tích cực về quản trị. Tuy nhiên, cần xem xét báo cáo kiểm toán và báo cáo tài chính đầy đủ để đưa ra đánh giá chính xác.'),
('VSG_2023_consolidated', 'VSG', 2023, 'consolidated', NULL, NULL, NULL, 5, NULL),
('VSG_2021_consolidated', 'VSG', 2021, 'consolidated', 'Không phát hiện giao dịch bất thường với bên liên quan. Công ty có cổ đông lớn là Công ty Cổ phần Mua Bán nợ Phương Đông (24,90% vốn điều lệ) nhưng không phát sinh giao dịch mua bán, vay mượn hay chuyển giá. Các thành viên quản lý chủ chốt không có giao dịch hay công nợ với Công ty.', 'Áp lực nợ vay rất lớn. Nợ ngắn hạn vượt tài sản ngắn hạn 570,4 tỷ VND. Toàn bộ khoản vay ngân hàng mua tàu (315,5 tỷ VND) đã quá hạn thanh toán do Công ty thiếu luồng tiền. Tài sản thế chấp bao gồm tàu và bất động sản đầu tư. Công ty đang đàm phán với ngân hàng để điều chỉnh kế hoạch trả nợ.', 'Hàng tồn kho nguyên vật liệu tăng từ 609 triệu lên 2 tỷ VND, mức tăng không đáng kể. Dự án xây dựng dở dang chủ yếu là chi phí mua phần mềm máy tính (1,56 tỷ VND), không có dự án bất động sản lớn bị ứ đọng.', 7, 'Công ty trong tình trạng tài chính khó khăn nghiêm trọng với lỗ luỹ kế 701,7 tỷ VND, âm vốn chủ sở hữu 534,5 tỷ VND. Nợ ngắn hạn vượt tài sản ngắn hạn, khả năng hoạt động liên tục bị nghi ngờ. Lỗ luỹ kế vượt vốn góp, toàn bộ vay ngân hàng quá hạn. Tuy nhiên, Công ty đang đàm phán với ngân hàng để điều chỉnh kế hoạch trả nợ phù hợp. Triển vọng đầu tư tiêu cực do rủi ro mất khả năng thanh toán cao.'),
('VSG_2020_consolidated', 'VSG', 2020, 'consolidated', 'Công ty không phát sinh giao dịch bán hàng, cung cấp dịch vụ hay các giao dịch khác với các thành viên quản lý chủ chốt và bên liên quan. Cổ đông lớn là Công ty Cổ phần Mua Bán nợ Phương Đông (24,90% vốn điều lệ) nhưng không có công nợ hay giao dịch. Rủi ro từ giao dịch bên liên quan thấp.', 'Công ty có nợ vay ngân hàng ngắn hạn lớn đã quá hạn (347,917,124,050 VND), nợ ngắn hạn (708,570,273,582 VND) vượt tài sản ngắn hạn (153,632,972,651 VND) 554,937,300,931 VND, lỗ lũy kế 597,783,541,974 VND vượt vốn chủ sở hữu 430,583,916,820 VND. Công ty đang gặp khó khăn về luồng tiền, nợ lãi vay đã quá hạn. Tuy nhiên, khoản vay được đảm bảo bằng tài sản hình thành từ vốn vay và bất động sản.', 'Hàng tồn kho có giá trị thấp (608,700,435 VND), giảm so với đầu năm. Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho không đáng kể.', 8, 'Công ty đang trong tình trạng tài chính nghiêm trọng với lỗ lũy kế lớn, nợ vay quá hạn, khả năng hoạt động liên tục bị nghi ngờ. Doanh thu chủ yếu từ cho thuê tàu (94,47%) nhưng giá vốn cao dẫn đến lỗ gộp. Công ty có nợ phải thu lớn từ hai khách hàng tập trung (Nam Phát Đạt và Global Solution P&T) với dự phòng nợ phải thu khó đòi tăng mạnh. Ngân hàng TMCP Hàng hải Việt Nam đang hỗ trợ điều chỉnh kế hoạch trả nợ. Triển vọng đầu tư tiêu cực do rủi ro thanh khoản và mất khả năng thanh toán.'),
('VSG_2019_consolidated', 'VSG', 2019, 'consolidated', 'Công ty không phát sinh giao dịch bán hàng, cung cấp dịch vụ hay các giao dịch khác với các thành viên quản lý chủ chốt, cá nhân có liên quan và các bên liên quan khác (Công ty Cổ phần Mua Bán nợ Phương Đông là cổ đông lớn 24,90% nhưng không có giao dịch). Rủi ro giao dịch bên liên quan thấp.', 'Nợ vay ngắn hạn lớn (362,45 tỷ VND) đã quá hạn thanh toán toàn bộ, áp lực trả nợ rất cao. Công ty đang gặp khó khăn về dòng tiền, lỗ lũy kế lớn. Tài sản thế chấp là bất động sản và tàu biển. Công ty đang đàm phán với ngân hàng để tái cơ cấu nợ.', 'Tồn kho thấp (dưới 1 tỷ VND), chủ yếu là nguyên liệu vật liệu, không có hàng tồn kho dở dang hay dự án xây dựng dở dang. Rủi ro tồn kho thấp.', 7, 'Công ty hoạt động chính trong lĩnh vực cho thuê tàu biển, đang trong tình trạng tài chính rất khó khăn với lỗ lũy kế lớn (558 tỷ VND), vốn chủ sở hữu âm (-391 tỷ VND), nợ ngắn hạn vượt xa tài sản ngắn hạn. Khả năng hoạt động liên tục phụ thuộc hoàn toàn vào việc đàm phán thành công với Ngân hàng TMCP Hàng hải Việt Nam để tái cơ cấu nợ vay. Điểm sáng duy nhất là không có giao dịch bên liên quan bất thường và doanh thu năm 2019 tăng trưởng mạnh so với 2018.'),
('VSG_2018_consolidated', 'VSG', 2018, 'consolidated', 'Công ty không phát sinh giao dịch với các bên liên quan, rủi ro liên quan thấp.', 'Áp lực nợ vay cao, toàn bộ nợ vay ngắn hạn đã quá hạn thanh toán, công ty đang đàm phán với ngân hàng để điều chỉnh kế hoạch trả nợ.', 'Hàng tồn kho là nguyên liệu vật liệu, giá trị không lớn, không có dự phòng, rủi ro thấp.', 7, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế 523 tỷ VND và nợ ngắn hạn vượt tài sản ngắn hạn 528 tỷ VND. Nợ vay ngân hàng đã quá hạn, tuy nhiên công ty đang đàm phán để điều chỉnh kế hoạch trả nợ. Doanh thu tăng nhưng vẫn lỗ do chi phí tài chính lớn. Triển vọng đầu tư rủi ro cao.');
PRAGMA foreign_keys = ON;
